insert into public.universities (id, country, name, verified, data) values ($sq$toronto$sq$, $sq$Canada$sq$, $sq$University of Toronto$sq$, true, $sq${"id":"toronto","name":"University of Toronto","country":"Canada","city":"Toronto (St. George, Scarborough & Mississauga campuses)","flag":"🇨🇦","ranking":"#1 in Canada in all five broad subject fields — top 17 globally in each (QS 2026 by subject)","knownFor":["Computer Science","Medicine","Engineering","Business","Arts & Humanities"],"language":"English-medium instruction","entryGrades":"Highly competitive — requirements vary by programme and campus; confirm on the official site.","tests":"IELTS / TOEFL required; the minimum varies by programme — confirm on the official site.","acceptance":"Highly competitive — varies significantly by programme","tuitionIntl":"First-year international tuition ~CAD $63,570 (~$46,400 USD) for Arts, Science, Computer Science, Management and most programmes — Fall 2026 estimate per the official UTSC admissions fees page (final 2026-27 fees approved April 2026). Year 2+ rises (e.g. Management CAD $74,430). Plus ~CAD $2,271/yr incidental fees.","living":"Toronto is one of Canada's most expensive cities — budget above the national estimate (~$17,000 USD/yr country figure); confirm current figures.","deadline":"Apply via OUAC — deadlines vary by programme and are not verified; confirm on future.utoronto.ca.","scholarshipsHere":"Lester B. Pearson International Scholarship — full ride (tuition, books, fees, 4 years residence) but requires nomination by your school; one student per school per year.","scholarships":[{"name":"Lester B. Pearson International Scholarship","percentage":"Full ride — tuition + books + fees + 4 years residence (~CAD 350,000 total)","whoQualifies":"International students in their final year of secondary school, nominated by their school (one per school per year)","howToApply":"School nomination first, then U of T admission application, then scholarship application (deadlines run ~Oct–Nov)","deadlineMonth":11,"amountTier":1,"level":"Undergraduate","verified":true}],"sourceName":"University of Toronto Scarborough admissions (official)","sourceUrl":"https://www.utsc.utoronto.ca/admissions/tuition-and-fees","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$ubc$sq$, $sq$Canada$sq$, $sq$University of British Columbia (UBC)$sq$, true, $sq${"id":"ubc","name":"University of British Columbia (UBC)","country":"Canada","city":"Vancouver (+ Okanagan campus, Kelowna)","flag":"🇨🇦","ranking":"One of Canada's top 3 — consistently in the QS global top ~50","knownFor":["Computer Science","Engineering","Business","Science","Environment & Forestry"],"language":"English-medium instruction","entryGrades":"Highly competitive — holistic admission (grades + personal profile); confirm per programme.","tests":"IELTS 6.5 / TOEFL — confirm the exact minimum per programme on the official site.","acceptance":"Highly competitive — varies by faculty","tuitionIntl":"International per-credit rates for the 2026 entry cohort (verified, UBC Academic Calendar): Arts $1,717.68, Science $1,769.40, Applied Science (Engineering) $1,789.18, Commerce $2,222.61 per credit → a standard 30-credit year ≈ CAD $51,500–$66,700 (~$37,600–$48,700 USD).","living":"Vancouver is one of Canada's most expensive cities — budget well above the national estimate; confirm current figures.","deadline":"Application opens early October and closes January 15 (11:59pm PST) for September entry; document deadlines Jan 31–Mar 15 by applicant type (verified for 2027 entry).","scholarshipsHere":"International Scholars Program (need + merit, application required) and the International Major Entrance Scholarship $10,000–$25,000/yr with automatic consideration. UBC Okanagan adds an $8,000 first-year Global Elevation Award from Sept 2026.","scholarships":[{"name":"International Scholars Program","percentage":"Need- and merit-based awards covering a significant part of costs (value varies by financial need)","whoQualifies":"High academic achievers with significant financial need and exceptional extracurricular/community involvement","howToApply":"Apply to UBC by ~Nov 15 and submit the Scholars application by ~Dec 1 (verified for Sept 2027 entry)","deadlineMonth":12,"amountTier":1,"level":"Undergraduate","verified":true},{"name":"International Major Entrance Scholarship (IMES)","percentage":"$10,000–$25,000 CAD/yr (2026/27 values), renewable up to 3 additional years","whoQualifies":"New international students entering directly from secondary school with exceptional achievement — excluded if nominated for International Scholars","howToApply":"Automatic consideration when you apply by the admission deadline — no separate application; decisions mid-Feb to late April","amountTier":2,"level":"Undergraduate","verified":true}],"sourceName":"UBC (official calendar & admissions)","sourceUrl":"https://vancouver.calendar.ubc.ca/fees/tuition-fees/undergraduate","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$mcgill$sq$, $sq$Canada$sq$, $sq$McGill University$sq$, false, $sq${"id":"mcgill","name":"McGill University","country":"Canada","city":"Montreal","flag":"🇨🇦","ranking":"#27 QS World 2026 · #1 in Canada","knownFor":["Medicine","Law","Engineering","Management","Arts & Science"],"language":"English-medium instruction (no French required, though Montreal is francophone)","entryGrades":"Highly competitive — grade-based admission; requirements vary by faculty. Confirm on the official site.","tests":"IELTS / TOEFL required; the minimum varies by programme — confirm on the official site.","acceptance":"Highly competitive — varies by faculty","tuitionIntl":"Not verified — McGill publishes international rates only through its fee calculator and per-faculty documents (mcgill.ca/student-accounts); confirm there before budgeting. Verified detail: international bachelor's students get a GUARANTEED flat tuition rate for their entire degree once enrolled.","living":"Montreal is more affordable than Toronto or Vancouver — a rough guide; confirm current figures.","deadline":"Not verified — confirm application deadlines on mcgill.ca.","scholarshipsHere":"McCall MacBain Scholarships — full funding for master's/professional degrees (up to 30 full scholarships + ~100 entrance awards/yr). Undergraduate entrance scholarships also exist — confirm on the official site.","scholarships":[{"name":"McCall MacBain Scholarships","percentage":"Full graduate scholarship — tuition & fees plus a living stipend","whoQualifies":"All nationalities. 2027 cohort: finishing your first bachelor's by Aug 2027, or earned it Jan 2021 or later, or were ≤30 on Jan 1, 2026","howToApply":"Apply at mccallmacbainscholars.org — international deadline 19 Aug 2026 4pm ET (Canada/US: 23 Sept 2026) for 2027 entry; interviews follow","deadlineMonth":8,"amountTier":1,"level":"Postgraduate","verified":true}],"sourceName":"McGill University (official)","sourceUrl":"https://www.mcgill.ca/student-accounts/tuition-fees","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$waterloo$sq$, $sq$Canada$sq$, $sq$University of Waterloo$sq$, true, $sq${"id":"waterloo","name":"University of Waterloo","country":"Canada","city":"Waterloo (Ontario)","flag":"🇨🇦","ranking":"Canada's co-op powerhouse — renowned for Computer Science, Engineering & Mathematics","knownFor":["Computer Science","Engineering","Mathematics","Accounting & Finance","Environment"],"language":"English-medium instruction","entryGrades":"Highly competitive for CS/Engineering (90%+ averages common); varies by programme — confirm on the official site.","tests":"IELTS / TOEFL required; the minimum varies by programme — confirm on the official site.","acceptance":"Highly competitive in CS/Engineering; varies by programme","tuitionIntl":"First-year fees for September 2026 entry, INCLUDING incidental fees (verified, uwaterloo.ca): Environment ~CAD $51,000; Science/Health ~$54,000; Arts ~$58,000; Mathematics ~$62,000; Computer Science ~$73,000; Engineering/Software Engineering/Architecture ~$75,000 (~$37,200–$54,800 USD). Books ~$1,500; co-op fee $836 per work term. Accounting/finance tuition rises significantly in upper years.","living":"Waterloo is cheaper than Toronto; co-op work terms (paid) offset costs for most students — confirm current figures.","deadline":"Apply via OUAC — programme deadlines not verified; confirm on the official site.","scholarshipsHere":"Automatic $10,000 first-year entrance scholarship for all eligible international students, plus larger competitive faculty awards (Science: $25,000–$80,000; Mathematics: $12,000–$40,000).","scholarships":[{"name":"International Student Entrance Scholarship","percentage":"$10,000 CAD — first year only ($5,000 toward each of the first two terms)","whoQualifies":"All international fee-paying students entering a full-time first-year degree (Sept 2026) — no minimum average. Excludes MD/Optometry/Pharmacy/Social Work and transfer students","howToApply":"Automatic — no application; appears in the applicant portal from April","amountTier":3,"level":"Undergraduate","verified":true},{"name":"Faculty of Science International Student Scholarships","percentage":"$25,000–$80,000 (15 awards)","whoQualifies":"International students entering Faculty of Science programmes","howToApply":"Application required — deadline was Feb 13, 2026 for this cycle; confirm next cycle on uwaterloo.ca","deadlineMonth":2,"amountTier":2,"level":"Undergraduate","verified":true}],"sourceName":"University of Waterloo (official)","sourceUrl":"https://uwaterloo.ca/future-students/financing/tuition","verified":true}$sq$::jsonb);
