insert into public.universities (id, country, name, verified, data) values ($sq$calgary$sq$, $sq$Canada$sq$, $sq$University of Calgary$sq$, true, $sq${"id":"calgary","name":"University of Calgary","country":"Canada","city":"Calgary","flag":"🇨🇦","ranking":"U15 research university — strong energy-industry links","knownFor":["Engineering","Business","Science","Nursing","Kinesiology"],"language":"English-medium instruction","entryGrades":"Competitive — requirements vary by faculty; confirm on the official site.","tests":"IELTS / TOEFL required; the minimum varies by programme — confirm on the official site.","acceptance":"Competitive — varies by faculty","tuitionIntl":"International rates effective Spring 2026 (verified, calendar.ucalgary.ca, per 3-unit course — 10 courses ≈ a full year): most faculties $3,078.21/course → ~CAD $30,782/yr (~$22,500 USD); Haskayne Business $3,610.44 → ~$36,104/yr (~$26,400); Schulich Engineering $4,148.73 → ~$41,487/yr (~$30,300). Medicine (MD) $37,893.93/term.","living":"Calgary is more affordable than Toronto/Vancouver — confirm current figures.","deadline":"Not verified — confirm on ucalgary.ca.","scholarshipsHere":"International Entrance Scholarship — $20,000 renewable through year 4, but only two awards per year.","scholarships":[{"name":"International Entrance Scholarship","percentage":"$20,000 CAD, renewable in years 2–4 (GPA 2.60+ over 24 units/yr)","whoQualifies":"International students entering first year of any undergraduate degree — academic merit; only TWO awards per year, extremely competitive","howToApply":"Via the My UCalgary portal \"High School Prestige Awards\" application (deadline ~Dec 1 for fall entry)","deadlineMonth":12,"amountTier":2,"level":"Undergraduate","verified":true}],"sourceName":"University of Calgary (official calendar)","sourceUrl":"https://calendar.ucalgary.ca/tuitionandfees","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$dalhousie$sq$, $sq$Canada$sq$, $sq$Dalhousie University$sq$, true, $sq${"id":"dalhousie","name":"Dalhousie University","country":"Canada","city":"Halifax (Nova Scotia)","flag":"🇨🇦","ranking":"Atlantic Canada's leading research university (U15)","knownFor":["Engineering","Computer Science","Management","Ocean & Marine Sciences","Health"],"language":"English-medium instruction","entryGrades":"Moderately competitive — requirements vary by faculty; confirm on the official site.","tests":"IELTS / TOEFL required; the minimum varies by programme — confirm on the official site.","acceptance":"Moderately competitive — varies by faculty","tuitionIntl":"International tuition for the 2026-27 entering cohort — GUARANTEED for the standard program length + 1 year (verified, dal.ca): Agriculture CAD $30,906; Arts & Social Sciences / Science $37,992; Computer Science $41,688; Management $42,042; Engineering $48,594 (~$22,600–$35,500 USD). Incidental and co-op fees extra; mandatory health insurance is included in student fees.","living":"Halifax is notably cheaper than Canada's big cities — confirm current figures.","deadline":"Not verified — confirm on dal.ca.","scholarshipsHere":"Entrance awards exist for international students — confirm current options on the official site.","scholarships":[],"sourceName":"Dalhousie University (official — International Tuition Guarantee)","sourceUrl":"https://www.dal.ca/admissions/money_matters/tuition_payments/International_Tuition_Guarantee.html","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$sfu$sq$, $sq$Canada$sq$, $sq$Simon Fraser University (SFU)$sq$, true, $sq${"id":"sfu","name":"Simon Fraser University (SFU)","country":"Canada","city":"Burnaby / Vancouver (British Columbia)","flag":"🇨🇦","ranking":"Major BC public university — strong co-op options across programmes","knownFor":["Computing Science","Business","Engineering","Communication","Interactive Arts"],"language":"English-medium instruction","entryGrades":"Moderately competitive — more accessible than UBC for many programmes; confirm per programme.","tests":"IELTS / TOEFL required; the minimum varies by programme — confirm on the official site.","acceptance":"Moderately competitive — varies by programme","tuitionIntl":"International tuition per the official Fall 2026 calendar (verified, sfu.ca — 2024/25+ entry cohort): base $1,262.88/unit → ~CAD $37,886/yr at 30 units (~$27,700 USD). Upper-division premiums: Computing Science $1,327.97, Engineering $1,348.19, Beedie Business $1,492.13/unit → up to ~CAD $44,764/yr (~$32,700 USD). Annual increases capped at ~6% for continuing students.","living":"Vancouver-area living costs are high — budget well above the national estimate; confirm current figures.","deadline":"Not verified — confirm on sfu.ca.","scholarshipsHere":"Entrance scholarships exist for international students — confirm current options on the official site.","scholarships":[],"sourceName":"Simon Fraser University (official calendar)","sourceUrl":"https://www.sfu.ca/students/calendar/fees-and-regulations/tuition-fees/undergraduate.html","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$memorial$sq$, $sq$Canada$sq$, $sq$Memorial University of Newfoundland$sq$, true, $sq${"id":"memorial","name":"Memorial University of Newfoundland","country":"Canada","city":"St. John's (Newfoundland)","flag":"🇨🇦","ranking":"Among the cheapest anglophone universities in Canada — popular budget pick for international students","knownFor":["Engineering","Marine & Ocean Sciences","Computer Science","Business","Nursing"],"language":"English-medium instruction","entryGrades":"Accessible relative to Canada's big research universities; varies by programme — confirm on the official site.","tests":"IELTS / TOEFL required; the minimum varies by programme — confirm on the official site.","acceptance":"Accessible — varies by programme","tuitionIntl":"International undergraduate tuition CAD $22,500 for two semesters / 10 courses (~$16,400 USD/yr) — 2025-26, verified on mun.ca. Mandatory fees ~CAD $923/yr (services, union, recreation, health insurance). Residence CAD $4,987–$5,993/semester. 2026-27 fees were pending review at research time — confirm before budgeting.","living":"St. John's is one of Canada's most affordable university cities — confirm current figures.","deadline":"Not verified — confirm intakes and deadlines on mun.ca.","scholarshipsHere":"Entrance scholarships exist — confirm current options on the official site.","scholarships":[],"sourceName":"Memorial University (official)","sourceUrl":"https://www.mun.ca/undergrad/money-matters/","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$qu$sq$, $sq$Qatar$sq$, $sq$Qatar University (QU)$sq$, true, $sq${"id":"qu","name":"Qatar University (QU)","country":"Qatar","city":"Doha","flag":"🇶🇦","ranking":"Qatar's national university — the country's largest by far","knownFor":["Engineering","Business","Law","Pharmacy","Medicine","Islamic Studies"],"language":"Mixed — many programmes are English-medium (especially Engineering, Business and Health); others are Arabic-medium. Confirm per programme.","entryGrades":"Varies by college; the full International Students Scholarship requires a 95%+ high school average. Confirm per programme.","tests":"English-taught programmes require IELTS / TOEFL; the minimum varies — confirm on the official site.","acceptance":"Competitive — varies by college","tuitionIntl":"Per credit hour for students admitted Fall 2023+ (verified, qu.edu.qa): Arts/Education/Law/Sharia QAR 1,100; Business/Sciences/Health/Nursing QAR 1,200; Engineering/Pharmacy QAR 1,400 → ~QAR 33,000–42,000/yr at 30 credit hours (~$9,050–$11,550 USD). Medicine and Dental Medicine charge annual fees instead — confirm on the official site.","living":"Doha living is moderate (rough country estimate ~$8,000–$13,000/yr) — scholarship holders get free university housing with campus transport; confirm current figures.","deadline":"Fall and Spring intakes — application windows not verified; confirm on qu.edu.qa.","scholarshipsHere":"Exceptional full scholarships: the International Students Scholarship (95%+ average) covers tuition, books, housing, annual flights and a stipend; the Talent Scholarship (80%+ with documented talent) adds guaranteed programme admission.","scholarships":[{"name":"International Students Scholarship","percentage":"Full package — tuition + textbooks + housing with transport + annual round-trip airfare + QAR 500/month stipend + residence permit","whoQualifies":"Direct-entry international undergraduates with a 95%+ high school average and final QU acceptance (no transfers/visiting/second-degree)","howToApply":"Via the \"Scholarship Application\" section of the QU online admission application during announced periods","amountTier":1,"level":"Undergraduate","verified":true},{"name":"Talent Scholarship","percentage":"Tuition + textbooks + QAR 1,000/month; internationals also get housing, transport, airfare and residence permit","whoQualifies":"80%+ high school average PLUS documented excellence in research, tech/innovation, literature, media or sports; two recommendation letters + portfolio","howToApply":"Online admission portal with supporting documents and videos during application periods; guarantees admission to your desired programme if minimum requirements are met","amountTier":1,"level":"Undergraduate","verified":true}],"sourceName":"Qatar University (official)","sourceUrl":"https://www.qu.edu.qa/en-us/students/admission/undergraduate/Pages/tuition-fees.aspx","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$cmu-q$sq$, $sq$Qatar$sq$, $sq$Carnegie Mellon University in Qatar (CMU-Q)$sq$, true, $sq${"id":"cmu-q","name":"Carnegie Mellon University in Qatar (CMU-Q)","country":"Qatar","city":"Doha (Education City)","flag":"🇶🇦","ranking":"Branch campus of Carnegie Mellon (US) — same degree as the Pittsburgh campus","knownFor":["Computer Science","Information Systems","Business Administration","Biological Sciences"],"language":"English-medium instruction","entryGrades":"Highly competitive — CMU-calibre admission; confirm requirements on the official site.","tests":"IELTS / TOEFL required; the minimum varies — confirm on the official site.","acceptance":"Highly competitive","tuitionIntl":"Same tuition as CMU Pittsburgh — $69,702 for 2026-27 (verified via the official cmu.edu fee schedule; parity policy per CMU-Q admissions). Qatar Foundation need-based grants of up to the FULL cost of attendance are available to students of all nationalities.","living":"Doha living is moderate (rough estimate ~$8,000–$13,000/yr); Education City has on-campus housing — confirm current figures.","deadline":"Not verified — confirm on qatar.cmu.edu.","scholarshipsHere":"Qatar Foundation need-based grants up to the full cost of attendance, for all nationalities — the sticker price is US-level but realistic affordability depends on QF aid.","scholarships":[{"name":"Qatar Foundation need-based grants","percentage":"Up to the full cost of attendance, based on family financial circumstances","whoQualifies":"Admitted students of all nationalities with demonstrated financial need","howToApply":"Through the CMU-Q financial aid process alongside your admission application","amountTier":1,"level":"Undergraduate","verified":true}],"sourceName":"Carnegie Mellon University (official fee schedule) & CMU-Q","sourceUrl":"https://www.qatar.cmu.edu/admission/how-to-apply/tuition-and-financial-aid/","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$gu-q$sq$, $sq$Qatar$sq$, $sq$Georgetown University in Qatar (GU-Q)$sq$, true, $sq${"id":"gu-q","name":"Georgetown University in Qatar (GU-Q)","country":"Qatar","city":"Doha (Education City)","flag":"🇶🇦","ranking":"Branch campus of Georgetown University (US) — Bachelor of Science in Foreign Service","knownFor":["International Politics","International Economics","Culture & Politics","International History"],"language":"English-medium instruction","entryGrades":"Highly competitive — Georgetown-calibre admission; confirm requirements on the official site.","tests":"IELTS / TOEFL required; the minimum varies — confirm on the official site.","acceptance":"Highly competitive","tuitionIntl":"Same tuition as Georgetown in Washington DC — $74,520 for 2026-27 (verified, studentaccounts.georgetown.edu) plus ~$2,172 in activity, insurance and textbook fees.","living":"Doha living is moderate (rough estimate ~$8,000–$13,000/yr); Education City has on-campus housing — confirm current figures.","deadline":"Not verified — confirm on qatar.georgetown.edu.","scholarshipsHere":"NEED-BLIND admission — GU-Q commits to meeting demonstrated financial need through grants, scholarships and sponsorships; the majority of students receive some form of aid.","scholarships":[{"name":"GU-Q need-based financial aid","percentage":"Meets demonstrated financial need (grants, scholarships, sponsorships)","whoQualifies":"Admitted students with demonstrated need — admission itself is need-blind","howToApply":"Submit the financial aid application alongside your admission application","amountTier":1,"level":"Undergraduate","verified":true}],"sourceName":"Georgetown University in Qatar (official)","sourceUrl":"https://www.qatar.georgetown.edu/admissions/financial-aid/tuition-and-fees/","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$nu-q$sq$, $sq$Qatar$sq$, $sq$Northwestern University in Qatar (NU-Q)$sq$, true, $sq${"id":"nu-q","name":"Northwestern University in Qatar (NU-Q)","country":"Qatar","city":"Doha (Education City)","flag":"🇶🇦","ranking":"Branch campus of Northwestern University (US) — same degree as Evanston","knownFor":["Journalism","Communication","Media Industries & Technology"],"language":"English-medium instruction","entryGrades":"Highly competitive; confirm requirements on the official site.","tests":"IELTS / TOEFL required; the minimum varies — confirm on the official site.","acceptance":"Highly competitive","tuitionIntl":"Tuition $71,802 for 2026-27 (verified, my.qatar.northwestern.edu); total with fees $73,990 off-campus or $80,090 on-campus. Textbook fee $1,000, health fee ~$894.","living":"Doha living is moderate (rough estimate ~$8,000–$13,000/yr); on-campus option adds ~$6,100/yr — confirm current figures.","deadline":"Applies via the Common App — deadlines not verified; confirm on qatar.northwestern.edu.","scholarshipsHere":"A limited number of highly competitive merit scholarships (automatic consideration), Qatar Foundation interest-free education loans, and on-campus jobs at QAR 45–60/hour (up to 20 hrs/week).","scholarships":[{"name":"NU-Q merit scholarships & QF interest-free loans","percentage":"Merit awards (limited, competitive) + zero-interest QF education loans","whoQualifies":"All applicants are automatically evaluated for merit awards; QF loans are need-based and open to all nationalities","howToApply":"Merit: automatic with your application. QF loans: apply after submitting the Common App","amountTier":2,"level":"Undergraduate","verified":true}],"sourceName":"Northwestern University in Qatar (official)","sourceUrl":"https://my.qatar.northwestern.edu/finance/tuition.html","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$wcm-q$sq$, $sq$Qatar$sq$, $sq$Weill Cornell Medicine – Qatar (WCM-Q)$sq$, true, $sq${"id":"wcm-q","name":"Weill Cornell Medicine – Qatar (WCM-Q)","country":"Qatar","city":"Doha (Education City)","flag":"🇶🇦","ranking":"Branch of Weill Cornell Medical College (US) — the only US MD degree available in the Gulf","knownFor":["Medicine","Pre-medical Sciences","Biomedical Research"],"language":"English-medium instruction","entryGrades":"Extremely competitive — medical-school admission standards; confirm on the official site.","tests":"IELTS / TOEFL required; the minimum varies — confirm on the official site.","acceptance":"Extremely competitive","tuitionIntl":"Medical curriculum tuition $71,505 for 2025-26 (verified, qatar-weill.cornell.edu — same tuition as Weill Cornell New York). Tuition is billed by Qatar Foundation, not the college.","living":"Doha living is moderate (rough estimate ~$8,000–$13,000/yr); Education City has on-campus housing — confirm current figures.","deadline":"Not verified — confirm on qatar-weill.cornell.edu.","scholarshipsHere":"Non-Qatari students may be eligible for Qatar Foundation need-based ZERO-INTEREST loans; Qatari citizens are funded through the Ministry of Education & Higher Education.","scholarships":[],"sourceName":"Weill Cornell Medicine – Qatar (official)","sourceUrl":"https://qatar-weill.cornell.edu/admissions/medical-program/four-year-medical-curriculum/tuition","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$hbku$sq$, $sq$Qatar$sq$, $sq$Hamad Bin Khalifa University (HBKU)$sq$, true, $sq${"id":"hbku","name":"Hamad Bin Khalifa University (HBKU)","country":"Qatar","city":"Doha (Education City)","flag":"🇶🇦","ranking":"Qatar Foundation's own research university — primarily graduate (master's/PhD) programmes","knownFor":["Computing & AI","Sustainability & Energy","Biomedical Sciences","Islamic Finance","Law","Public Policy"],"language":"English-medium instruction","entryGrades":"Graduate admission — a strong bachelor's degree is required; criteria vary by programme.","tests":"IELTS / TOEFL required; the minimum varies — confirm on the official site.","acceptance":"Competitive — most admitted students are funded","tuitionIntl":"QAR 4,000/credit for STEM programmes and QAR 2,500/credit for humanities/social sciences and law (verified from the official scholarship policy) — but most admitted students receive 60–100% tuition waivers plus stipends. Self-sponsored need-based rate QAR 2,000/credit.","living":"Doha living is moderate (rough estimate ~$8,000–$13,000/yr); funded students often receive accommodation — confirm current figures.","deadline":"Not verified — confirm on hbku.edu.qa.","scholarshipsHere":"Generous automatic scholarships: 100% tuition waivers for PhD, 75% for STEM master's, 60% for humanities/law master's, plus monthly stipends of QAR 4,000–11,000.","scholarships":[{"name":"HBKU Graduate Scholarships","percentage":"Tuition waivers: PhD 100%, master's STEM 75%, humanities/law 60% + stipends QAR 4,000–11,000/month","whoQualifies":"Admitted full-time master's/PhD students — merit- and need-based, fund-dependent; professionals working >40% time are ineligible for stipends","howToApply":"Automatic consideration during admissions — no separate application","amountTier":1,"level":"Postgraduate","verified":true}],"sourceName":"Hamad Bin Khalifa University (official scholarship guidelines)","sourceUrl":"https://www.hbku.edu.qa/en/scholarship","verified":true}$sq$::jsonb);
