insert into public.universities (id, country, name, verified, data) values ($sq$doha-institute$sq$, $sq$Qatar$sq$, $sq$Doha Institute for Graduate Studies (DI)$sq$, false, $sq${"id":"doha-institute","name":"Doha Institute for Graduate Studies (DI)","country":"Qatar","city":"Doha","flag":"🇶🇦","ranking":"Independent graduate-only institute — social sciences, humanities & public policy","knownFor":["Social Sciences","Humanities","Public Policy","Development Economics","Media Studies"],"language":"Primarily Arabic-medium with English components — confirm per programme.","entryGrades":"Graduate admission — a strong bachelor's degree is required; criteria vary by programme.","tests":"Language requirements vary (Arabic and/or English) — confirm on the official site.","acceptance":"Competitive","tuitionIntl":"Not verified — confirm on dohainstitute.edu.qa.","living":"Doha living is moderate (rough estimate ~$8,000–$13,000/yr) — confirm current figures.","deadline":"Admissions run annually (the official site showed 2027-28 deadlines at research time) — confirm on dohainstitute.edu.qa.","scholarshipsHere":"CAUTION: aggregator sites heavily advertise a \"fully funded Tamim bin Hamad Scholarship\" (tuition + housing + stipend + flights, ~Jan 15 deadline), but DI's official scholarships page listed NO scholarships when checked in July 2026. Verify current availability directly with DI admissions before planning around it.","scholarships":[],"sourceName":"Doha Institute for Graduate Studies (official)","sourceUrl":"https://www.dohainstitute.edu.qa/en/Admissions-Office/Pages/Scholarships.aspx","verified":false}$sq$::jsonb);
