insert into public.universities (id, country, name, verified, data) values ($sq$nyuad$sq$, $sq$UAE$sq$, $sq$New York University Abu Dhabi (NYUAD)$sq$, true, $sq${"id":"nyuad","name":"New York University Abu Dhabi (NYUAD)","country":"UAE","city":"Abu Dhabi (Saadiyat Island)","flag":"🇦🇪","ranking":"Full degree-granting NYU campus — among the most selective universities in the world","knownFor":["Liberal Arts & Sciences","Engineering","Computer Science","Economics","Film & New Media"],"language":"English-medium instruction","entryGrades":"Extremely competitive, holistic admission — finalists attend a Candidate Weekend in Abu Dhabi before final decisions.","tests":"Test-flexible policies change — confirm current requirements on the official site.","acceptance":"Extremely competitive — one of the lowest acceptance rates anywhere","tuitionIntl":"Sticker price 2026-27 (verified, nyuad.nyu.edu): tuition $68,576; total cost of attendance ~$90,328 (NYU housing and meal plan are required). But need-based aid via the CSS Profile is exceptional — many students pay far less, and every admitted student is considered for merit support.","living":"Housing and meals are part of the required (and aid-covered) cost of attendance.","deadline":"Verified: Early Decision I Nov 1, Early Decision II Jan 1, Regular Decision Jan 5 (Common App); CSS Profile due Nov 10 / Jan 10 / Feb 1 respectively.","scholarshipsHere":"Need-based financial aid can cover most or all of the ~$90,328 cost of attendance — submit the CSS Profile by the deadline. Every admitted student is also considered for limited merit-based support.","scholarships":[{"name":"NYUAD Need-based Financial Aid","percentage":"Up to the full cost of attendance, based on demonstrated need (CSS Profile)","whoQualifies":"All admitted students who demonstrate financial need — all nationalities","howToApply":"Submit the CSS Profile by Nov 10 (ED I), Jan 10 (ED II) or Feb 1 (Regular Decision)","deadlineMonth":2,"amountTier":1,"level":"Undergraduate","verified":true}],"sourceName":"NYU Abu Dhabi (official)","sourceUrl":"https://nyuad.nyu.edu/en/apply/undergraduate/scholarships-and-financial-aid/cost-of-attendance.html","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$khalifa$sq$, $sq$UAE$sq$, $sq$Khalifa University$sq$, true, $sq${"id":"khalifa","name":"Khalifa University","country":"UAE","city":"Abu Dhabi","flag":"🇦🇪","ranking":"The UAE's flagship STEM and research university","knownFor":["Engineering","Computer Science","Aerospace","Petroleum Engineering","Medicine"],"language":"English-medium instruction","entryGrades":"Competitive STEM admission; requirements vary by programme — confirm on the official site.","tests":"IELTS / TOEFL / EmSAT required; the minimum varies — confirm on the official site.","acceptance":"Competitive — scholarship tiers are more competitive still","tuitionIntl":"AED 2,500 per credit hour (verified, ku.ac.ae) → ~AED 75,000/yr at 30 credit hours (~$20,400 USD) — but tiered scholarships waive 25–100% of tuition for strong international admits, with automatic consideration.","living":"Abu Dhabi living costs are significant (country estimate ~$16,000/yr) — confirm current figures.","deadline":"Not verified — confirm on ku.ac.ae.","scholarshipsHere":"Five automatic scholarship tiers for international students: 100%, 75%, 50%, 25% or 0% tuition waivers, all with free textbooks. Slots are limited and merit-based.","scholarships":[{"name":"KU Undergraduate Scholarships (Tiers I–IV)","percentage":"25–100% tuition waiver + free textbooks","whoQualifies":"International bachelor applicants, mapped to a tier on academic merit during admission; limited slots, not guaranteed","howToApply":"Automatic — assessed during the admission process, no separate application","amountTier":1,"level":"Undergraduate","verified":true}],"sourceName":"Khalifa University (official)","sourceUrl":"https://www.ku.ac.ae/scholarships-undergraduate","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$uaeu$sq$, $sq$UAE$sq$, $sq$United Arab Emirates University (UAEU)$sq$, false, $sq${"id":"uaeu","name":"United Arab Emirates University (UAEU)","country":"UAE","city":"Al Ain (Abu Dhabi emirate)","flag":"🇦🇪","ranking":"The UAE's national/federal university — the country's oldest","knownFor":["Engineering","IT","Business","Law","Medicine","Education"],"language":"English-medium for most programmes; some Arabic — confirm per programme.","entryGrades":"Competitive; requirements vary by college — confirm on the official site.","tests":"IELTS / TOEFL / EmSAT required; the minimum varies — confirm on the official site.","acceptance":"Competitive — varies by college","tuitionIntl":"Per official UAEU student-account pages (stated valid through 2025-26; the site was unreachable for direct confirmation — treat with care): AED 1,900/credit hour for Humanities/Education/Law, AED 2,300 for Business, AED 2,500 for Engineering/IT/Health → ~AED 57,000–75,000/yr (~$15,500–$20,400 USD). On-campus housing is available for international students.","living":"Al Ain is cheaper than Dubai/Abu Dhabi city — confirm current figures.","deadline":"Not verified — confirm on uaeu.ac.ae.","scholarshipsHere":"Confirm current international scholarships on the official site.","scholarships":[],"sourceName":"UAEU (official)","sourceUrl":"https://www.uaeu.ac.ae/en/dvcsae/student_account_office/program-and-housing-rates-international-students-undergraduate-students.shtml","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$aus$sq$, $sq$UAE$sq$, $sq$American University of Sharjah (AUS)$sq$, true, $sq${"id":"aus","name":"American University of Sharjah (AUS)","country":"UAE","city":"Sharjah","flag":"🇦🇪","ranking":"American-curriculum private university — one of the Gulf's best known","knownFor":["Engineering","Architecture","Business","Design","International Studies"],"language":"English-medium instruction","entryGrades":"Competitive; requirements vary by programme — confirm on the official site.","tests":"IELTS / TOEFL required; the minimum varies — confirm on the official site.","acceptance":"Competitive — varies by programme","tuitionIntl":"AED 110,876/yr for all majors in 2026-27 (verified, aus.edu) — AED 55,438 per semester for 12–16 credits (~$30,200 USD/yr). Technology fees may apply per semester.","living":"Sharjah is cheaper than Dubai (adjacent emirate) — confirm current figures.","deadline":"Not verified — confirm on aus.edu.","scholarshipsHere":"AUS offers merit scholarships and financial grants — confirm current options on aus.edu.","scholarships":[],"sourceName":"American University of Sharjah (official)","sourceUrl":"https://www.aus.edu/admissions/bachelors-degrees/undergraduate-tuition-and-fees","verified":true}$sq$::jsonb);
