insert into public.universities (id, country, name, verified, data) values ($sq$rit-dubai$sq$, $sq$UAE$sq$, $sq$RIT Dubai (Rochester Institute of Technology)$sq$, true, $sq${"id":"rit-dubai","name":"RIT Dubai (Rochester Institute of Technology)","country":"UAE","city":"Dubai (Silicon Oasis)","flag":"🇦🇪","ranking":"Dubai campus of RIT (US) — same US degree, strong co-op/industry orientation","knownFor":["Cybersecurity","Computing","Engineering","Finance","New Media Design"],"language":"English-medium instruction","entryGrades":"Moderately competitive; varies by programme — confirm on the official site.","tests":"IELTS / TOEFL required; the minimum varies — confirm on the official site.","acceptance":"Moderately competitive","tuitionIntl":"AED 68,000/yr flat across all bachelor programmes for students admitted Fall 2023+ (verified, rit.edu/dubai — official USD figure $18,516). Extras: AED 2,500 enrolment deposit, ~AED 500/semester books, AED 860 lab fee per applicable course.","living":"Dubai is one of the pricier Gulf cities — confirm current figures.","deadline":"Not verified — confirm on rit.edu/dubai.","scholarshipsHere":"Merit scholarships up to 50% based on academic AND non-academic accomplishments; athletic scholarships also available.","scholarships":[{"name":"RIT Dubai Merit Scholarships","percentage":"Up to 50% of tuition","whoQualifies":"Applicants with strong academic and non-academic accomplishments; athletic awards also exist","howToApply":"Via RIT Dubai's scholarships page alongside your admission application","amountTier":2,"level":"Undergraduate","verified":true}],"sourceName":"RIT Dubai (official)","sourceUrl":"https://www.rit.edu/dubai/tuition-and-fees","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$mbzuai$sq$, $sq$UAE$sq$, $sq$Mohamed bin Zayed University of Artificial Intelligence (MBZUAI)$sq$, true, $sq${"id":"mbzuai","name":"Mohamed bin Zayed University of Artificial Intelligence (MBZUAI)","country":"UAE","city":"Abu Dhabi (Masdar City)","flag":"🇦🇪","ranking":"Graduate-only AI research university — one of the world's first dedicated AI universities","knownFor":["Machine Learning","Computer Vision","NLP","Robotics","Computational Biology"],"language":"English-medium instruction","entryGrades":"Graduate admission — strong quantitative bachelor's degree required; highly competitive.","tests":"IELTS / TOEFL required; GRE requirements vary — confirm on the official site.","acceptance":"Highly competitive","tuitionIntl":"Effectively FREE for admitted students — every full-time MSc/PhD student receives a 100% tuition scholarship plus a monthly stipend (verified, mbzuai.ac.ae). Does not apply to the MAAI programme.","living":"Stipend (AED 15,500–17,500/month for internationals) is designed to cover living costs; optional on-campus housing AED 7,500/month is deducted from it.","deadline":"Verified for the 2026 intake: priority Nov 15, final Dec 15 for most programmes (CompBio & HCI final Feb 27); decisions Mar 15.","scholarshipsHere":"Full funding for all admitted MSc/PhD students: 100% tuition, monthly stipend (international: AED 15,500 MSc / AED 17,500 PhD), visa sponsorship and health insurance.","scholarships":[{"name":"MBZUAI Graduate Scholarship","percentage":"100% tuition + monthly stipend (AED 15,500 MSc / AED 17,500 PhD for internationals) + visa + health insurance","whoQualifies":"ALL admitted full-time MSc/PhD students (excludes the MAAI programme); requires maintaining high academic standing","howToApply":"Automatic with admission — apply by Nov 15 (priority) / Dec 15 (final) for most programmes","deadlineMonth":12,"amountTier":1,"level":"Postgraduate","verified":true}],"sourceName":"MBZUAI (official)","sourceUrl":"https://mbzuai.ac.ae/study/graduate-admission-process/","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$ajman$sq$, $sq$UAE$sq$, $sq$Ajman University$sq$, false, $sq${"id":"ajman","name":"Ajman University","country":"UAE","city":"Ajman","flag":"🇦🇪","ranking":"Private university in the northern emirates — among the UAE's more affordable options","knownFor":["Dentistry","Pharmacy","Engineering","Business","Mass Communication"],"language":"English and Arabic — confirm per programme.","entryGrades":"Accessible relative to the flagship universities; varies by programme — confirm on the official site.","tests":"IELTS / TOEFL / EmSAT vary by programme — confirm on the official site.","acceptance":"Accessible — varies by programme","tuitionIntl":"Not verified — the official fee brochure could not be parsed during research (a third-party example cites ~AED 1,300/credit hour for Engineering; treat as unconfirmed). Confirm on ajman.ac.ae.","living":"Ajman is one of the cheapest emirates to live in — confirm current figures.","deadline":"Not verified — confirm on ajman.ac.ae.","scholarshipsHere":"Confirm current scholarships on the official site.","scholarships":[],"sourceName":"Ajman University (official)","sourceUrl":"https://www.ajman.ac.ae/en/admissions/undergraduate/tuition-fees","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$kaust$sq$, $sq$Saudi Arabia$sq$, $sq$King Abdullah University of Science and Technology (KAUST)$sq$, true, $sq${"id":"kaust","name":"King Abdullah University of Science and Technology (KAUST)","country":"Saudi Arabia","city":"Thuwal (near Jeddah)","flag":"🇸🇦","ranking":"Graduate-only elite STEM research university — every admitted student is funded","knownFor":["AI & Computer Science","Bioscience","Materials Science","Earth & Marine Science","Electrical Engineering"],"language":"English-medium instruction — fully international campus","entryGrades":"Graduate admission — strong STEM bachelor's/master's and research potential required; highly competitive.","tests":"IELTS / TOEFL required; GRE optional/varies — confirm on the official site.","acceptance":"Highly competitive","tuitionIntl":"Effectively FREE — the KAUST Fellowship (verified, admissions.kaust.edu.sa) covers full tuition & bench fees (value up to $35,000/yr), a stipend of $20,000/yr (MS) or $25,000–$30,000/yr (PhD), base housing, health insurance and relocation. Total value ~$70,000–$80,000/yr.","living":"Housing is included in the fellowship; KAUST is a self-contained international campus community on the Red Sea.","deadline":"Rolling/annual cycles — confirm on admissions.kaust.edu.sa.","scholarshipsHere":"The KAUST Fellowship is awarded with admission to full-time MS/PhD students (externally sponsored students may be ineligible) — no separate application.","scholarships":[{"name":"KAUST Fellowship","percentage":"Full tuition + $20,000–$30,000/yr stipend + housing + health insurance + relocation (~$70k–80k/yr total value)","whoQualifies":"Full-time admitted MS/PhD students (students with external sponsorship may be ineligible)","howToApply":"Automatic with admission — no separate application","amountTier":1,"level":"Postgraduate","verified":true}],"sourceName":"KAUST (official admissions)","sourceUrl":"https://admissions.kaust.edu.sa/fees-funding","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$kfupm$sq$, $sq$Saudi Arabia$sq$, $sq$King Fahd University of Petroleum and Minerals (KFUPM)$sq$, false, $sq${"id":"kfupm","name":"King Fahd University of Petroleum and Minerals (KFUPM)","country":"Saudi Arabia","city":"Dhahran","flag":"🇸🇦","ranking":"Saudi Arabia's top-ranked technical university — strong energy and engineering reputation","knownFor":["Petroleum Engineering","Engineering","Computer Science","Applied Sciences","Business"],"language":"English-medium instruction","entryGrades":"Highly competitive; varies by programme — confirm on the official site.","tests":"IELTS / TOEFL required; the minimum varies — confirm on the official site.","acceptance":"Highly competitive","tuitionIntl":"Non-Saudi undergraduates ~SR 20,000/yr (~$5,300 USD) per official pages — not directly confirmed (kfupm.edu.sa blocked access during research); need/merit undergraduate scholarships exist. Graduate students: full scholarships covering tuition, stipend, housing, flights, meals and medical care.","living":"On-campus housing is part of graduate scholarships; Dhahran/Khobar living is moderate — confirm current figures.","deadline":"Not verified — confirm on kfupm.edu.sa.","scholarshipsHere":"Full graduate scholarships for all PhD programmes (and MS programmes without a corresponding PhD): tuition-free study, monthly stipend, free furnished on-campus housing, air tickets, medical/dental care, subsidized meals and free textbooks.","scholarships":[{"name":"KFUPM Graduate Scholarship","percentage":"Full funding — tuition + stipend + housing + flights + meals + medical care + textbooks","whoQualifies":"Distinguished MS/PhD applicants in engineering, sciences and business (all PhD programmes; MS programmes without a corresponding PhD)","howToApply":"Apply for graduate admission at kfupm.edu.sa — confirm current cycles on the official site","amountTier":1,"level":"Postgraduate","verified":false}],"sourceName":"KFUPM (official)","sourceUrl":"https://www.kfupm.edu.sa/study/international-students/fees-and-scholarships","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$ksu$sq$, $sq$Saudi Arabia$sq$, $sq$King Saud University (KSU)$sq$, false, $sq${"id":"ksu","name":"King Saud University (KSU)","country":"Saudi Arabia","city":"Riyadh","flag":"🇸🇦","ranking":"Saudi Arabia's oldest and largest university","knownFor":["Medicine","Engineering","Sciences","Business","Arabic Language Institute"],"language":"Arabic and English (STEM/medicine largely English) — confirm per programme.","entryGrades":"Competitive — scholarship seats are heavily oversubscribed; varies by college.","tests":"Varies by programme — confirm on the official site.","acceptance":"Scholarship route is very competitive","tuitionIntl":"Internationals mainly come via FULL scholarships rather than paying tuition: the verified Distinguished Graduate Studentship for PhD (tuition + SAR 54,000/yr living allowance + housing + health coverage + up to 1 year post-graduation work authorization) and general full scholarships via the Study in Saudi platform. Self-funded tuition rates not verified.","living":"Scholarship students get on-campus housing; Riyadh living is moderate — confirm current figures.","deadline":"Periodic scholarship windows (the 2025 PhD window closed May 15; phases announced each Fall) — confirm on ksu.edu.sa or studyinsaudi.moe.gov.sa.","scholarshipsHere":"Distinguished Graduate Studentship (PhD, verified) plus general full international scholarships via the official Study in Saudi platform.","scholarships":[{"name":"KSU Distinguished Graduate Studentship (PhD)","percentage":"Full tuition + SAR 54,000/yr (~$14,400) living allowance + housing + health coverage + 1-yr post-graduation work authorization","whoQualifies":"Master's degree holders from accredited institutions; TOEFL iBT 61+ / IELTS 6+ (waived for degrees from US/CA/UK/IE/AU/NZ)","howToApply":"Via dgsinitiative.ksu.edu.sa during announced windows","amountTier":1,"level":"Postgraduate","verified":true}],"sourceName":"King Saud University (official DGS initiative)","sourceUrl":"https://dgsinitiative.ksu.edu.sa/","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$kau$sq$, $sq$Saudi Arabia$sq$, $sq$King Abdulaziz University (KAU)$sq$, false, $sq${"id":"kau","name":"King Abdulaziz University (KAU)","country":"Saudi Arabia","city":"Jeddah","flag":"🇸🇦","ranking":"One of Saudi Arabia's largest and highest-ranked universities","knownFor":["Engineering","Medicine","Sciences","Business","Marine Sciences"],"language":"Arabic and English — confirm per programme.","entryGrades":"Competitive — varies by college; confirm on the official site.","tests":"Varies by programme — confirm on the official site.","acceptance":"Scholarship route is competitive","tuitionIntl":"For internationals the route is external scholarships — official pages describe full scholarships (monthly bursary + accommodation + healthcare + two-way airfare + arrival allowance) for bachelor's and postgraduate applicants residing outside Saudi Arabia. Benefit specifics not directly confirmed (the official page would not render); apply via kau.edu.sa or the Study in Saudi platform.","living":"Scholarship students receive accommodation; Jeddah living is moderate — confirm current figures.","deadline":"Not verified — confirm on kau.edu.sa.","scholarshipsHere":"External full scholarships for overseas applicants (bachelor's and postgraduate) — apply via the official portals.","scholarships":[],"sourceName":"King Abdulaziz University (official)","sourceUrl":"https://kau.edu.sa/en/page/international-student-scholarships","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$iu-madinah$sq$, $sq$Saudi Arabia$sq$, $sq$Islamic University of Madinah$sq$, false, $sq${"id":"iu-madinah","name":"Islamic University of Madinah","country":"Saudi Arabia","city":"Madinah","flag":"🇸🇦","ranking":"Public university focused on Islamic studies and Arabic, plus science/engineering colleges — MEN ONLY","knownFor":["Islamic Studies","Arabic Language","Sharia","Engineering","Computer Science"],"language":"Arabic-medium primarily (free intensive Arabic preparation); some science programmes use English — confirm per programme.","entryGrades":"Undergraduate applicants typically aged ~17–25 with a high school diploma; competitive.","tests":"Arabic proficiency developed via the university's own programme; requirements vary — confirm on the official site.","acceptance":"Competitive — large international intake","tuitionIntl":"Via full scholarships — aggregators consistently report a monthly allowance + furnished housing + healthcare + flight on admission and annual return tickets + excellence bonuses. Not directly verified — confirm via the Study in Saudi platform (studyinsaudi.moe.gov.sa).","living":"Scholarship covers housing and stipend; Madinah living is moderate.","deadline":"Reported ~mid-June for undergraduate (2026 cycle) — not verified; master's reportedly accepted year-round. Confirm on iu.edu.sa.","scholarshipsHere":"Full scholarships for admitted international students (male only) — apply via the Study in Saudi platform.","scholarships":[],"sourceName":"Islamic University of Madinah (official)","sourceUrl":"https://iu.edu.sa/","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$uqu$sq$, $sq$Saudi Arabia$sq$, $sq$Umm Al-Qura University$sq$, false, $sq${"id":"uqu","name":"Umm Al-Qura University","country":"Saudi Arabia","city":"Makkah","flag":"🇸🇦","ranking":"Public university in Islam's holiest city — Islamic studies, Arabic, plus medicine/engineering","knownFor":["Islamic Law (Sharia)","Arabic for Non-Native Speakers","Medicine","Engineering"],"language":"Arabic-medium primarily — confirm per programme.","entryGrades":"Varies by college — confirm on the official site.","tests":"Varies by programme — confirm on the official site.","acceptance":"Competitive — varies by programme","tuitionIntl":"Via internal (resident) and external (overseas) scholarships — full awards reportedly cover tuition + monthly stipend + housing + annual airfare + health insurance; partial awards exist. Benefit specifics not directly verified; apply via uqu.edu.sa or the Study in Saudi platform.","living":"Scholarship students are housed; Makkah living is moderate.","deadline":"Not verified — confirm on uqu.edu.sa.","scholarshipsHere":"Full and partial scholarships for international students — apply via the official portals. Note: non-Muslims cannot reside/study in Makkah's holy district, so this university is realistic only for Muslim applicants.","scholarships":[],"sourceName":"Umm Al-Qura University (official)","sourceUrl":"https://uqu.edu.sa/en","verified":false}$sq$::jsonb);
