insert into public.universities (id, country, name, verified, data) values ($sq$ut-tehran$sq$, $sq$Iran$sq$, $sq$University of Tehran (UT)$sq$, false, $sq${"id":"ut-tehran","name":"University of Tehran (UT)","country":"Iran","city":"Tehran","flag":"🇮🇷","ranking":"Iran's oldest and most prestigious comprehensive university","knownFor":["Engineering","Law & Political Science","Humanities","Natural Sciences","Persian Literature"],"language":"Mostly Persian-medium (prep courses offered); some graduate programmes have English options — confirm per programme.","entryGrades":"Competitive; requirements vary by faculty — confirm on the official site.","tests":"Persian proficiency for most programmes (prep year available); English tests for English-taught options — confirm per programme.","acceptance":"Competitive — Iran's flagship","tuitionIntl":"Per official-derived sources (the official fee page was redirect-blocked during research — confirm on ut.ac.ir): ~$850–$2,150 per semester by field → roughly $1,700–$4,300/yr. Excludes housing and living costs, which are very low in USD terms.","living":"Iran living costs are among the lowest anywhere (~$150–$250/month per official TUMS guidance) — sanctions complicate money transfers, plan payments carefully.","deadline":"Not verified — confirm on international.ut.ac.ir.","scholarshipsHere":"UT grants partial scholarships (monthly stipend + insurance + registration fees) to roughly 20% of international applicants after CV review; MSRT government scholarships also place students here.","scholarships":[{"name":"UT International Scholarships","percentage":"Partial — monthly stipend + insurance + registration fees","whoQualifies":"Roughly 20% of international applicants, selected by CV review","howToApply":"With the international admission application at international.ut.ac.ir","amountTier":2,"level":"Undergraduate","verified":false}],"sourceName":"University of Tehran (official)","sourceUrl":"https://international.ut.ac.ir/en/page/790","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$sharif$sq$, $sq$Iran$sq$, $sq$Sharif University of Technology$sq$, true, $sq${"id":"sharif","name":"Sharif University of Technology","country":"Iran","city":"Tehran","flag":"🇮🇷","ranking":"Iran's premier engineering/technology university — famously strong alumni in global tech and academia","knownFor":["Electrical & Computer Engineering","Mechanical Engineering","Physics","Mathematics","Aerospace"],"language":"Persian-medium at bachelor's (prep courses available); some English-taught graduate options — confirm per programme.","entryGrades":"Highly competitive — merit-based regardless of nationality; confirm on the official site.","tests":"Persian for undergrad (prep available); English-taught grad programmes typically want IELTS ~6.0–6.5 — confirm per programme.","acceptance":"Highly competitive","tuitionIntl":"Verified (en.sharif.ir/admission): undergraduate €1,000 fixed per semester + €20 per unit; graduate €1,100 fixed + €40 per unit → roughly €2,700–€3,000/yr. Excludes housing, insurance and living costs. Self-supported applicants must show funds for ≥1 year of living costs.","living":"Iran living costs are very low in USD terms; the university's conservative bank-letter figure is $14,000/yr — actual spending typically runs far lower.","deadline":"Not verified — confirm on en.sharif.ir.","scholarshipsHere":"MSRT government scholarship placements possible — apply via msrt.ir / saorg.ir.","scholarships":[],"sourceName":"Sharif University of Technology (official)","sourceUrl":"https://en.sharif.ir/admission","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$tums$sq$, $sq$Iran$sq$, $sq$Tehran University of Medical Sciences (TUMS)$sq$, false, $sq${"id":"tums","name":"Tehran University of Medical Sciences (TUMS)","country":"Iran","city":"Tehran","flag":"🇮🇷","ranking":"Iran's top medical university — largest English-taught international programme","knownFor":["Medicine (MD)","Dentistry","Pharmacy","Public Health","Nursing"],"language":"English-taught programmes for international students","entryGrades":"Fee level and reductions depend on your GPA/scores; competitive — confirm on the official site.","tests":"IELTS 5.5 (or equivalent) required by registration time — a low bar compared with Western medical schools.","acceptance":"Competitive — more accessible than Western medical schools","tuitionIntl":"MD $5,000–$7,500/yr depending on GPA/scores for the September 2026 intake, locked for your cohort once admitted (per official-derived sources — the official fee page redirect-looped during research; confirm on en.tums.ac.ir). Undergraduate fee reductions by prior GPA. No application fee; applications open year-round.","living":"Official TUMS guidance: ~$150–$200/month for a moderate student life — among the cheapest anywhere.","deadline":"Applications open year-round for set intakes — confirm on en.tums.ac.ir.","scholarshipsHere":"TUMS advertises fee reductions by academic merit; MSRT government scholarships also place students in Iranian universities. IMPORTANT: verify MD degree recognition in the country where you plan to practise BEFORE enrolling.","scholarships":[],"sourceName":"Tehran University of Medical Sciences (official)","sourceUrl":"https://en.tums.ac.ir/en/page/10/fee-structure","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$al-mustafa$sq$, $sq$Iran$sq$, $sq$Al-Mustafa International University (MIU)$sq$, false, $sq${"id":"al-mustafa","name":"Al-Mustafa International University (MIU)","country":"Iran","city":"Qom","flag":"🇮🇷","ranking":"International religious university — students from 120+ countries","knownFor":["Islamic Studies","Theology","Quranic Sciences","Persian & Arabic Language","Islamic Law"],"language":"Persian and Arabic (language preparation provided).","entryGrades":"Entrance examination; extremely selective (single-digit acceptance rates reported).","tests":"Entrance examination; language preparation provided after admission.","acceptance":"Extremely selective","tuitionIntl":"Reportedly FREE for admitted students — tuition, monthly stipend, housing and family support covered (third-party sources; not directly verified — confirm with miu.ac.ir).","living":"Covered by the scholarship per reports; Qom living costs are very low.","deadline":"Not verified — confirm on miu.ac.ir.","scholarshipsHere":"Full scholarship for admitted students (reported: tuition + stipend + housing + family support). Religious institution — realistic only for students seeking Islamic education; expectations of religious observance apply.","scholarships":[{"name":"Al-Mustafa Full Scholarship","percentage":"Reportedly free tuition + monthly stipend + housing + family support","whoQualifies":"Admitted students seeking Islamic education (entrance exam; extremely selective)","howToApply":"Via miu.ac.ir admissions","amountTier":1,"level":"Undergraduate","verified":false}],"sourceName":"Al-Mustafa International University (official)","sourceUrl":"https://miu.ac.ir/portal/?lang=en","verified":false}$sq$::jsonb);
