insert into public.universities (id, country, name, verified, data) values ($sq$tartu$sq$, $sq$Estonia$sq$, $sq$University of Tartu$sq$, true, $sq${"id":"tartu","name":"University of Tartu","country":"Estonia","city":"Tartu","flag":"🇪🇪","ranking":"Estonia's flagship university (founded 1632) — the leading university in the Baltics","knownFor":["Computer Science","Medicine","Genetics & Life Sciences","Semiotics","Educational Technology"],"language":"Wide range of English-taught bachelor's and master's programmes.","entryGrades":"Competitive — selection by grades, motivation letters and programme-specific criteria; confirm per programme.","tests":"IELTS / TOEFL required for English programmes; the minimum varies — confirm on ut.ee.","acceptance":"Competitive — varies by programme","tuitionIntl":"Per-programme fees are in the official 2026/27 fee documents on ut.ee (typical Estonian range €3,000–€8,000/yr; medicine higher) — confirm your programme's figure. IMPORTANT (verified): from 2026/27 there are NO tuition waivers for new non-EU/EEA students — selected programmes instead grant automatic 25/50/100% fee reductions. PhD is tuition-free.","living":"Tartu is a compact, affordable student city (~€500–€700/month rough estimate) — confirm current figures.","deadline":"Applications via DreamApply, generally winter–spring for autumn intake — confirm on ut.ee.","scholarshipsHere":"Automatic tuition-fee reductions of 25–100% in selected programmes (no separate application; requires full-time status and 30+ ECTS from semester 2), plus the Estonian National Scholarship stipend (€350/month) for citizens of ~37 approved countries.","scholarships":[{"name":"UT Tuition-Fee Reductions","percentage":"25%, 50% or 100% fee reduction, one semester at a time (selected programmes)","whoQualifies":"Qualifying admitted students — automatic, no application; from semester 2 requires full-time status and ≥30 ECTS cumulatively","howToApply":"Automatic with admission (from 2026/27 these replace the old non-EU tuition waivers)","amountTier":1,"level":"Undergraduate","verified":true}],"sourceName":"University of Tartu (official)","sourceUrl":"https://ut.ee/en/content/cost-tuition","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$taltech$sq$, $sq$Estonia$sq$, $sq$Tallinn University of Technology (TalTech)$sq$, false, $sq${"id":"taltech","name":"Tallinn University of Technology (TalTech)","country":"Estonia","city":"Tallinn","flag":"🇪🇪","ranking":"Estonia's technical university — strong IT/engineering, core of \"e-Estonia\" talent","knownFor":["IT & Computer Science","Cyber Security","Engineering","Business","Maritime"],"language":"Many English-taught programmes at all levels.","entryGrades":"Competitive — programme-specific criteria; confirm on taltech.ee.","tests":"IELTS / TOEFL required; the minimum varies — confirm on taltech.ee.","acceptance":"Competitive — varies by programme","tuitionIntl":"EU/EEA citizens are tuition-EXEMPT except in the School of Business and Governance (verified). Non-EU fees ~€2,300–€6,000/yr per official-derived sources, set per programme — confirm on the programme page. Fees may rise up to 10%/yr for current students (verified clause).","living":"Tallinn is Estonia's priciest city but still moderate for Europe (~€600–€800/month rough estimate) — confirm current figures.","deadline":"Via DreamApply — confirm on taltech.ee.","scholarshipsHere":"Limited tuition-fee waivers on all degree programmes for the best applicants (entire nominal period), €100/month merit scholarships after the first semester, and fully-funded places on selected master's programmes.","scholarships":[{"name":"TalTech Tuition-Fee Waivers","percentage":"Full tuition waiver for the nominal study period (limited, best applicants) + €100/month merit awards after semester 1","whoQualifies":"Top-ranked applicants to any degree programme","howToApply":"Considered with the admission application via DreamApply","amountTier":1,"level":"Undergraduate","verified":false}],"sourceName":"TalTech (official)","sourceUrl":"https://taltech.ee/en/tuition-fee-rates","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$tlu$sq$, $sq$Estonia$sq$, $sq$Tallinn University (TLU)$sq$, true, $sq${"id":"tlu","name":"Tallinn University (TLU)","country":"Estonia","city":"Tallinn","flag":"🇪🇪","ranking":"Estonia's humanities and social sciences-focused public university","knownFor":["Educational Innovation","Digital Learning Games","Human-Computer Interaction","Communication","Law","Audiovisual Media"],"language":"English-taught programmes at bachelor's and master's level.","entryGrades":"Moderately competitive; confirm per programme on tlu.ee.","tests":"IELTS / TOEFL required; the minimum varies — confirm on tlu.ee.","acceptance":"Moderately competitive","tuitionIntl":"2026/27 fees verified (tlu.ee): bachelor's €4,200–€5,400/yr (Liberal Arts in Humanities €4,200, Audiovisual Media €4,800, Law €5,400); master's €3,800–€6,000/yr (some programmes charge EU citizens less than non-EU). PhD is tuition-free. Three payment plans: annual, per-semester, or 8 instalments.","living":"Tallinn living ~€600–€800/month (rough estimate) — confirm current figures.","deadline":"Via DreamApply — confirm on tlu.ee.","scholarshipsHere":"Estonian National Scholarship stipend (€350/month, ~37 approved countries) can be combined; check tlu.ee for university awards.","scholarships":[],"sourceName":"Tallinn University (official 2026/27 fee table)","sourceUrl":"https://www.tlu.ee/en/tuition-fees","verified":true}$sq$::jsonb);
