insert into public.universities (id, country, name, verified, data) values ($sq$oxford$sq$, $sq$United Kingdom$sq$, $sq$University of Oxford$sq$, true, $sq${"id":"oxford","name":"University of Oxford","country":"United Kingdom","city":"Oxford","flag":"🇬🇧","ranking":"The English-speaking world's oldest university — perennial global top-5","knownFor":["PPE","Law","Medicine","Sciences","Humanities","Computer Science"],"language":"English-medium instruction","entryGrades":"The UK's most demanding — top grades (A*A*A-level equivalents), admissions tests and interviews for most courses.","tests":"IELTS 7.0–7.5 typically + course-specific admissions tests — confirm per course on ox.ac.uk.","acceptance":"Extremely competitive","tuitionIntl":"International tuition £37,380–£62,820/yr by course for 2026 entry (verified, ox.ac.uk); Medicine £49,400 pre-clinical rising to £65,250 in clinical years. International students are not eligible for UK government loans.","living":"Oxford is expensive; UK visa maintenance for outside-London is £1,171/month × 9 months — real Oxford costs run higher.","deadline":"UCAS by 15 October 2026, 6pm UK time, for 2027 entry (verified) — a full cycle earlier than most countries.","scholarshipsHere":"Rhodes Scholarship for postgraduates (full fees + £20,400/yr stipend + flights); undergraduate aid for internationals is very limited (e.g. Reach Oxford for students from low-income countries).","scholarships":[{"name":"Rhodes Scholarship (postgraduate)","percentage":"Full Oxford fees + £20,400/yr stipend + flights + visa & health surcharge","whoQualifies":"Ages 18–24 (to 25 for professional-degree internships), meeting your country constituency's citizenship rules; character/leadership-driven selection","howToApply":"Via your country constituency at rhodeshouse.ox.ac.uk — deadlines mostly July–October the year before entry","deadlineMonth":9,"amountTier":1,"level":"Postgraduate","verified":true}],"sourceName":"University of Oxford (official)","sourceUrl":"https://www.ox.ac.uk/admissions/undergraduate/fees-and-funding/course-fees","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$cambridge$sq$, $sq$United Kingdom$sq$, $sq$University of Cambridge$sq$, true, $sq${"id":"cambridge","name":"University of Cambridge","country":"United Kingdom","city":"Cambridge","flag":"🇬🇧","ranking":"Collegiate research university — perennial global top-5","knownFor":["Mathematics","Natural Sciences","Engineering","Computer Science","Medicine","Law"],"language":"English-medium instruction","entryGrades":"Top grades (A*A*A-level equivalents), admissions assessments and interviews.","tests":"IELTS 7.5 typically + course assessments — confirm per course on cam.ac.uk.","acceptance":"Extremely competitive","tuitionIntl":"International tuition £29,052–£70,554/yr by subject for 2026-27 (verified) PLUS an annual college fee of ~£11,500–£14,950 (some colleges discount it — Trinity's £19,557 nets to £13,689 after its 30% bursary). Budget both parts.","living":"Cambridge is expensive; outside-London visa maintenance rate applies (£1,171/month × 9).","deadline":"UCAS by 15 October 2026, 6pm UK time, for 2027 entry (verified).","scholarshipsHere":"Gates Cambridge for postgraduates — full fees + £21,000/yr + flights + visa/IHS + family allowances; undergraduate international aid is very limited.","scholarships":[{"name":"Gates Cambridge Scholarship (postgraduate)","percentage":"Full Composition Fee + £21,000/yr maintenance + flights + visa/IHS + academic & family allowances","whoQualifies":"International postgraduate applicants to Cambridge — leadership and commitment to improving others' lives weigh heavily (~80 awards/yr)","howToApply":"Tick the Gates Cambridge option inside the Cambridge graduate application; deadlines ~Oct (US) / Dec–Jan (others)","deadlineMonth":12,"amountTier":1,"level":"Postgraduate","verified":true}],"sourceName":"University of Cambridge (official)","sourceUrl":"https://www.undergraduate.study.cam.ac.uk/fees-funding/tuition-fees","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$imperial$sq$, $sq$United Kingdom$sq$, $sq$Imperial College London$sq$, false, $sq${"id":"imperial","name":"Imperial College London","country":"United Kingdom","city":"London","flag":"🇬🇧","ranking":"STEM + medicine + business only — consistently top-5 in world rankings","knownFor":["Engineering","Computing & AI","Medicine","Natural Sciences","Business"],"language":"English-medium instruction","entryGrades":"Extremely demanding STEM entry (A*A*A equivalents with specific subjects) — confirm per course.","tests":"IELTS 6.5–7.0 typically + course-specific tests — confirm on imperial.ac.uk.","acceptance":"Extremely competitive","tuitionIntl":"Fees are set per course — roughly £31,750–£55,800/yr per official-derived listings (confirm your course page on imperial.ac.uk).","living":"Central London — the higher £1,529/month × 9 visa maintenance rate applies, and real London costs often exceed it.","deadline":"UCAS by 13 January 2027 equal-consideration (medicine 15 October 2026) — verified.","scholarshipsHere":"President's Scholarships and departmental awards exist — check imperial.ac.uk; GREAT Scholarships (£10,000, selected countries) sometimes include Imperial.","scholarships":[],"sourceName":"Imperial College London (official)","sourceUrl":"https://www.imperial.ac.uk/study/fees-and-funding/undergraduate/tuition-fees/","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$lse$sq$, $sq$United Kingdom$sq$, $sq$London School of Economics and Political Science (LSE)$sq$, false, $sq${"id":"lse","name":"London School of Economics and Political Science (LSE)","country":"United Kingdom","city":"London","flag":"🇬🇧","ranking":"The world's leading dedicated social-science university","knownFor":["Economics","Finance","Politics","International Relations","Law","Data Science"],"language":"English-medium instruction","entryGrades":"Extremely demanding — top grades with strong mathematics for economics-side programmes.","tests":"IELTS 7.0 typically — confirm per programme on lse.ac.uk.","acceptance":"Extremely competitive","tuitionIntl":"Tiered by programme — ~£27,500–£34,000/yr at 2025/26 rates; the 2026/27 Table of Fees is published on lse.ac.uk (confirm your programme).","living":"Central London — higher £1,529/month × 9 visa maintenance rate applies.","deadline":"UCAS by 13 January 2027 equal-consideration (verified).","scholarshipsHere":"Undergraduate Support Scheme (need-based for internationals) and Graduate Support Scheme — check lse.ac.uk.","scholarships":[],"sourceName":"LSE (official Table of Fees)","sourceUrl":"https://info.lse.ac.uk/staff/divisions/Planning-Division/Table-of-Fees","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$ucl$sq$, $sq$United Kingdom$sq$, $sq$University College London (UCL)$sq$, false, $sq${"id":"ucl","name":"University College London (UCL)","country":"United Kingdom","city":"London","flag":"🇬🇧","ranking":"London's largest research university — huge international community","knownFor":["Architecture","Medicine","Computer Science","Education","Law","Engineering"],"language":"English-medium instruction","entryGrades":"Highly demanding (A*AA–AAB equivalents by course) — confirm per course.","tests":"IELTS 6.5–7.5 by course level — confirm on ucl.ac.uk.","acceptance":"Highly competitive","tuitionIntl":"Fees are set per programme — not verified here; confirm on ucl.ac.uk.","living":"Central London — higher £1,529/month × 9 visa maintenance rate applies.","deadline":"UCAS by 13 January 2027 equal-consideration (medicine 15 October 2026) — verified.","scholarshipsHere":"UCL Global Undergraduate Scholarship — full tuition (23 awards) or full tuition + maintenance (10 awards) for low-income international students; deadline was 27 April 2026 for the current cycle.","scholarships":[{"name":"UCL Global Undergraduate Scholarship","percentage":"Full tuition + maintenance (10 awards) OR full tuition only (23 awards)","whoQualifies":"International students (overseas fee status) from low-income backgrounds with financial need","howToApply":"Apply via ucl.ac.uk/scholarships after applying to UCL; deadline ~late April each cycle","deadlineMonth":4,"amountTier":1,"level":"Undergraduate","verified":true}],"sourceName":"UCL (official)","sourceUrl":"https://www.ucl.ac.uk/scholarships/","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$edinburgh$sq$, $sq$United Kingdom$sq$, $sq$University of Edinburgh$sq$, false, $sq${"id":"edinburgh","name":"University of Edinburgh","country":"United Kingdom","city":"Edinburgh (Scotland)","flag":"🇬🇧","ranking":"Scotland's flagship university — global top-30 heritage","knownFor":["Informatics & AI","Medicine","Law","Literature","Veterinary Medicine"],"language":"English-medium instruction","entryGrades":"Highly demanding; Scottish degrees run 4 years — confirm per course.","tests":"IELTS 6.5–7.0 typically — confirm on ed.ac.uk.","acceptance":"Highly competitive","tuitionIntl":"From ~£26,500/yr (2025/26 baseline; 2026-27 tables on registryservices.ed.ac.uk). Verified policy: international fees are FIXED at your entry-year rate for the whole degree. Remember Scottish degrees are 4 years, not 3.","living":"Edinburgh is cheaper than London — outside-London maintenance rate (£1,171/month × 9) applies.","deadline":"UCAS by 13 January 2027 equal-consideration (medicine/vet 15 October 2026) — verified.","scholarshipsHere":"Edinburgh Global scholarships and GREAT Scholarships (selected countries) — check ed.ac.uk.","scholarships":[],"sourceName":"University of Edinburgh (official)","sourceUrl":"https://registryservices.ed.ac.uk/tuition-fees/find/undergraduate/2026-2027","verified":false}$sq$::jsonb);
