insert into public.universities (id, country, name, verified, data) values ($sq$tudelft$sq$, $sq$Netherlands$sq$, $sq$Delft University of Technology (TU Delft)$sq$, true, $sq${"id":"tudelft","name":"Delft University of Technology (TU Delft)","country":"Netherlands","city":"Delft","flag":"🇳🇱","ranking":"The Netherlands' leading engineering university — global top-3 in several engineering subjects","knownFor":["Aerospace Engineering","Civil & Mechanical Engineering","Computer Science","Architecture","Industrial Design"],"language":"English-taught MSc programmes broadly; several English BSc options (English bachelor availability is under national policy pressure — confirm).","entryGrades":"Highly competitive — strong maths/physics required; numerus fixus selection for capped programmes.","tests":"IELTS / TOEFL required; the minimum varies — confirm on tudelft.nl.","acceptance":"Highly competitive","tuitionIntl":"Non-EU institutional fees 2026-27 (verified, tudelft.nl): BSc €19,906/yr, MSc €25,633/yr — rising year on year.","living":"Delft is a small student city near The Hague/Rotterdam (~€1,000–1,200/month realistic). Dutch student housing is in severe shortage — arrange before arrival.","deadline":"Numerus fixus programmes close 15 January (hard deadline, verified); MSc rounds vary — confirm on tudelft.nl. Apply via Studielink.","scholarshipsHere":"Justus & Louise van Effen Excellence Scholarships — ~€30,000/yr covering full tuition + living contribution for excellent non-EU MSc admits; deadline 1 December.","scholarships":[{"name":"Justus & Louise van Effen Excellence Scholarship","percentage":"~€30,000/yr — full tuition + living contribution (2-year MSc ≈ €60,000)","whoQualifies":"Excellent non-EU applicants (conditionally) admitted to a regular 2-year TU Delft MSc","howToApply":"Apply for MSc admission early, then the scholarship by 1 December for next-year intake","deadlineMonth":12,"amountTier":1,"level":"Postgraduate","verified":true}],"sourceName":"TU Delft (official)","sourceUrl":"https://www.tudelft.nl/en/education/study-programme-orientation/practical-matters/tuition-fee-finances","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$uva$sq$, $sq$Netherlands$sq$, $sq$University of Amsterdam (UvA)$sq$, false, $sq${"id":"uva","name":"University of Amsterdam (UvA)","country":"Netherlands","city":"Amsterdam","flag":"🇳🇱","ranking":"The Netherlands' largest comprehensive research university","knownFor":["Economics & Business","Psychology","Media Studies","Law","Social Sciences"],"language":"Many English-taught programmes (bachelor availability shrinking under national policy — confirm per programme).","entryGrades":"Competitive; numerus fixus selection for capped programmes like Psychology and PPLE.","tests":"IELTS / TOEFL required; the minimum varies — confirm on uva.nl.","acceptance":"Competitive — varies by programme","tuitionIntl":"Institutional fees are set per programme — typically ~€9,000–€20,000/yr for non-EU bachelor's (verified example: PPLE €19,100 for 2026-27). Confirm your programme on uva.nl.","living":"Amsterdam has the country's WORST student-housing shortage and highest costs (~€1,300–1,600/month realistic) — secure housing before accepting.","deadline":"Numerus fixus 15 January (hard); regular non-EU typically 1 April–1 May — apply via Studielink; confirm per programme.","scholarshipsHere":"Amsterdam Merit/Excellence awards vary by faculty — check uva.nl; the national NL Scholarship (€5,000 one-time) also applies at Dutch universities.","scholarships":[],"sourceName":"University of Amsterdam (official)","sourceUrl":"https://www.uva.nl/en/education/fees-and-funding/tuition-fees/tuition-fees.html","verified":false}$sq$::jsonb);
