insert into public.universities (id, country, name, verified, data) values ($sq$maastricht$sq$, $sq$Netherlands$sq$, $sq$Maastricht University$sq$, false, $sq${"id":"maastricht","name":"Maastricht University","country":"Netherlands","city":"Maastricht","flag":"🇳🇱","ranking":"The Netherlands' most international university — ~half the students are non-Dutch","knownFor":["Medicine","European Studies","Business & Economics","Psychology","Law"],"language":"Most programmes taught in English — the most international-friendly Dutch option.","entryGrades":"Competitive; Problem-Based Learning model suits self-directed students — confirm per programme.","tests":"IELTS / TOEFL required; the minimum varies — confirm on maastrichtuniversity.nl.","acceptance":"Competitive — varies by programme","tuitionIntl":"Institutional fees set per programme — confirm on maastrichtuniversity.nl.","living":"Maastricht is cheaper than the Randstad cities (~€900–1,200/month realistic); housing still tight.","deadline":"Numerus fixus 15 January (hard); others vary — apply via Studielink.","scholarshipsHere":"NL-High Potential Scholarship — 21 full packages of €34,000/yr (tuition waiver + stipend + insurance + visa costs) for non-EU master's students; deadline 1 February.","scholarships":[{"name":"NL-High Potential Scholarship","percentage":"€34,000/yr full package — tuition waiver + €12,350–€23,750 stipend + insurance + visa costs (21 awards)","whoQualifies":"Non-EU/EEA master's admits aged ≤35 with GPA ≥7.5/10","howToApply":"Apply by 1 February for the following academic year (verified for 2026-27)","deadlineMonth":2,"amountTier":1,"level":"Postgraduate","verified":true}],"sourceName":"Maastricht University (official)","sourceUrl":"https://www.maastrichtuniversity.nl/studeren/toelating-inschrijving/financing-your-studies/scholarships/maastricht-university-nl-high","verified":false}$sq$::jsonb);
