insert into public.universities (id, country, name, verified, data) values ($sq$thuas$sq$, $sq$Netherlands$sq$, $sq$The Hague University of Applied Sciences (THUAS)$sq$, false, $sq${"id":"thuas","name":"The Hague University of Applied Sciences (THUAS)","country":"Netherlands","city":"The Hague","flag":"🇳🇱","ranking":"Applied-sciences (HBO) sector — practice-oriented and typically cheaper than research universities","knownFor":["International Business","European Studies","Industrial Design Engineering","Law"],"language":"Many English-taught programmes — English bachelor availability is shrinking under national policy; confirm per programme.","entryGrades":"Varies by programme; capped (numerus fixus) programmes use selection — confirm on the official site.","tests":"IELTS / TOEFL required; the minimum varies — confirm on the official site.","acceptance":"Varies by programme","tuitionIntl":"Non-EU institutional fees are set per programme (Dutch range roughly €9,000–€22,000/yr; tech MSc higher) — NOT individually verified; confirm on the official site. HBO degrees are career-focused; check progression requirements if you plan a research master's later.","living":"Budget ~€900–€1,600/month by city. Dutch student housing is in severe shortage — secure housing before accepting an offer.","deadline":"Apply via Studielink: numerus fixus programmes close 15 January (hard, verified); regular non-EU deadlines typically 1 April–1 May.","scholarshipsHere":"NL Scholarship (€5,000 one-time, national) applies at Dutch universities; university-specific awards noted above — always confirm current status, several Dutch scholarships are being cut.","scholarships":[],"sourceName":"Official site","sourceUrl":"https://www.thehagueuniversity.com/study-choice","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$iit-bombay$sq$, $sq$India$sq$, $sq$IIT Bombay$sq$, false, $sq${"id":"iit-bombay","name":"IIT Bombay","country":"India","city":"Mumbai","flag":"🇮🇳","ranking":"India's most sought-after engineering institute","knownFor":["Computer Science","Electrical Engineering","Mechanical Engineering","Aerospace","Design"],"language":"English-medium instruction","entryGrades":"Foreign nationals need 75%+ in Class XII equivalent AND must clear JEE Advanced — one of the world's hardest entrance exams.","tests":"JEE Advanced (foreign nationals register directly, skipping JEE Main — verified); registration $100 SAARC / $200 others.","acceptance":"Extremely competitive — realistic only for exceptionally strong STEM students","tuitionIntl":"Fees vary by IIT and nationality and were not verified for IITB specifically (example: IIT Bhilai charges $25/credit for SAARC, $50/credit for others). Up to 10% supernumerary seats per course are reserved for foreign nationals (verified). Confirm on iitb.ac.in.","living":"India living costs are among the lowest anywhere (~$2,000–$4,000/yr); campus hostels are very cheap.","deadline":"Follows the JEE Advanced calendar (exam ~May–June, registration earlier) — confirm on jeeadv.ac.in.","scholarshipsHere":"ICCR full scholarships and Study in India waivers generally do NOT cover IIT admission — the JEE Advanced route is the door here.","scholarships":[],"sourceName":"IIT Bombay (official)","sourceUrl":"https://www.iitb.ac.in/","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$iit-delhi$sq$, $sq$India$sq$, $sq$IIT Delhi$sq$, false, $sq${"id":"iit-delhi","name":"IIT Delhi","country":"India","city":"New Delhi","flag":"🇮🇳","ranking":"Top-tier engineering institute in the capital","knownFor":["Computer Science","Electrical Engineering","Textile Technology","Management"],"language":"English-medium instruction","entryGrades":"Same JEE Advanced route as all IITs for foreign nationals (verified) — extremely demanding.","tests":"JEE Advanced; registration $100 SAARC / $200 others.","acceptance":"Extremely competitive","tuitionIntl":"Fees vary by IIT and nationality — not verified; confirm on iitd.ac.in.","living":"Delhi living costs are very low by international standards; campus hostels cheaper still.","deadline":"Follows the JEE Advanced calendar — confirm on jeeadv.ac.in.","scholarshipsHere":"See IIT Bombay note — ICCR/SII channels generally do not apply to IIT seats.","scholarships":[],"sourceName":"IIT Delhi (official)","sourceUrl":"https://home.iitd.ac.in/","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$nit-trichy$sq$, $sq$India$sq$, $sq$NIT Tiruchirappalli (NIT Trichy)$sq$, true, $sq${"id":"nit-trichy","name":"NIT Tiruchirappalli (NIT Trichy)","country":"India","city":"Tiruchirappalli (Tamil Nadu)","flag":"🇮🇳","ranking":"India's top-ranked NIT — representative of the 30+ NIT system open to internationals via DASA","knownFor":["Engineering (all branches)","Computer Science","Architecture"],"language":"English-medium instruction","entryGrades":"DASA allocates seats by merit ranking (recent cycles JEE Main-based — confirm current criteria on the portal).","tests":"Per current DASA criteria — confirm on dasanit.org.","acceptance":"Competitive — merit-ranked within the DASA pool","tuitionIntl":"Via the DASA scheme (verified for 2026): ~USD 4,000/semester for non-SAARC students; SAARC citizens get a 50% waiver. Hostels ~₹6,000/month + mess ~₹5,000/month. One DASA application covers NITs, IIITs and other centrally funded institutes.","living":"Small-city Indian living costs — extremely low.","deadline":"Annual DASA cycle (application ~April–June) — confirm on dasanit.org.","scholarshipsHere":"The SAARC 50% tuition waiver is built into DASA; CIWG category (Gulf-based Indian workers' children) pays Indian-level fees.","scholarships":[],"sourceName":"DASA (official scheme portal)","sourceUrl":"https://dasanit.org/","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$delhi-university$sq$, $sq$India$sq$, $sq$University of Delhi (DU)$sq$, false, $sq${"id":"delhi-university","name":"University of Delhi (DU)","country":"India","city":"New Delhi","flag":"🇮🇳","ranking":"India's most famous central university — dozens of colleges under one umbrella","knownFor":["Economics","Commerce","Law","English","Political Science"],"language":"English-medium instruction","entryGrades":"Foreign applicants are assessed on prior academics via the Foreign Students' Registry — no CUET needed for most international seats; confirm.","tests":"IELTS/TOEFL if your education was not in English — confirm on fsr.du.ac.in.","acceptance":"Competitive — supernumerary international seats","tuitionIntl":"Remarkably low — public fees apply to foreigners too (some programmes cost well under $500/yr; professional programmes more). All foreign admissions run through the Foreign Students' Registry — confirm current fees on fsr.du.ac.in.","living":"Delhi living is very cheap by global standards (~$150–$300/month for a modest student life).","deadline":"Annual FSR window roughly Feb–May for autumn entry — confirm on fsr.du.ac.in.","scholarshipsHere":"ICCR full scholarships place many students at DU; Study in India waivers may also apply. Nepal/Bangladesh/Bhutan/Tibet applicants need an NOC from their diplomatic mission.","scholarships":[],"sourceName":"University of Delhi Foreign Students' Registry (official)","sourceUrl":"https://fsr.du.ac.in/","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$sharda$sq$, $sq$India$sq$, $sq$Sharda University$sq$, false, $sq${"id":"sharda","name":"Sharda University","country":"India","city":"Greater Noida (Delhi NCR)","flag":"🇮🇳","ranking":"Private university with one of India's largest international cohorts (95+ nationalities)","knownFor":["Engineering","Business","Medical & Allied Sciences","Law"],"language":"English-medium instruction","entryGrades":"Accessible — admission on prior academics; scholarships scale with your scores.","tests":"English proficiency requirements vary — confirm on sharda.ac.in.","acceptance":"Accessible","tuitionIntl":"From ~$5,000/yr per the official global fee pages, plus a Global Course Fee of $500 (year 1) / $250 (later years) — waived for Nepal/Bhutan/Bangladesh and GCC NRIs. Confirm per programme on sharda.ac.in.","living":"Delhi NCR living is very cheap; on-campus hostels available.","deadline":"Rolling international admissions — confirm on sharda.ac.in.","scholarshipsHere":"Ambassador's Scholarship up to 100% of tuition for international applicants, scaled by academic merit — confirm current terms.","scholarships":[{"name":"Sharda Ambassador's Scholarship","percentage":"Up to 100% of tuition, scaled by prior academic merit","whoQualifies":"International UG/PG/doctoral applicants — level depends on scores","howToApply":"With the international admission application on sharda.ac.in","amountTier":1,"level":"Undergraduate","verified":false}],"sourceName":"Sharda University (official global fee pages)","sourceUrl":"https://www.sharda.ac.in/international/global-course-fee/","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$lpu$sq$, $sq$India$sq$, $sq$Lovely Professional University (LPU)$sq$, false, $sq${"id":"lpu","name":"Lovely Professional University (LPU)","country":"India","city":"Phagwara (Punjab)","flag":"🇮🇳","ranking":"One of India's largest private universities — huge campus, aggressive international recruitment","knownFor":["Engineering","Business","Agriculture","Hospitality","Computer Applications"],"language":"English-medium instruction","entryGrades":"Accessible — the LPU International Scholarship Test (LPUIST) doubles as entrance and scholarship assessment.","tests":"LPUIST for scholarships; English requirements vary — confirm on lpu.in/international.","acceptance":"Accessible","tuitionIntl":"LOW — third-party sources suggest from ~$1,000–$3,000/yr depending on programme (not verified; confirm on lpu.in/international). Flexible USD/INR payment options are advertised.","living":"Punjab living costs are very low; large on-campus residential system.","deadline":"Rolling — confirm on lpu.in/international.","scholarshipsHere":"Scholarships up to 60% via the LPU International Scholarship Test (LPUIST) plus country-specific awards — confirm current terms.","scholarships":[],"sourceName":"LPU International (official)","sourceUrl":"https://www.lpu.in/international/","verified":false}$sq$::jsonb);
