insert into public.universities (id, country, name, verified, data) values ($sq$auckland$sq$, $sq$New Zealand$sq$, $sq$University of Auckland$sq$, false, $sq${"id":"auckland","name":"University of Auckland","country":"New Zealand","city":"Auckland","flag":"🇳🇿","ranking":"New Zealand's largest and highest-ranked university","knownFor":["Engineering","Computer Science","Medicine","Business","Law"],"language":"English-medium instruction","entryGrades":"Competitive — assessed on national qualifications (A-Levels/IB/etc.); confirm per programme.","tests":"IELTS 6.0–6.5+ typically; higher for medicine/law — confirm on auckland.ac.nz.","acceptance":"Competitive — varies by faculty","tuitionIntl":"International tuition 2026: ~NZ$40,225–$58,120+/yr by faculty, plus a Student Services Fee of NZ$9.44/point (~NZ$1,133 full-time) — confirm per programme. PhD students pay the DOMESTIC rate (~NZ$8,000–9,000/yr, national policy, verified).","living":"Auckland is NZ's priciest city; the visa requires proof of NZ$20,000/yr living funds plus tuition plus a return ticket (verified).","deadline":"Apply directly — Semester 1 (Feb) applications generally close ~December, Semester 2 (Jul) ~May; confirm on auckland.ac.nz.","scholarshipsHere":"International Student Excellence Scholarships plus Manaaki New Zealand Scholarships (full package for 80+ developing countries). Post-study work visa up to 3 years for master's/PhD graduates.","scholarships":[],"sourceName":"University of Auckland (official)","sourceUrl":"https://www.auckland.ac.nz/en/study/fees-and-money-matters/tuition-fees/international-student-fees/undergraduate-international-fees.html","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$otago$sq$, $sq$New Zealand$sq$, $sq$University of Otago$sq$, false, $sq${"id":"otago","name":"University of Otago","country":"New Zealand","city":"Dunedin","flag":"🇳🇿","ranking":"New Zealand's oldest university — famous residential student culture","knownFor":["Medicine","Dentistry","Health Sciences","Sciences","Law"],"language":"English-medium instruction","entryGrades":"Competitive — health professional programmes very competitive; confirm per programme.","tests":"IELTS 6.0–6.5+ typically — confirm on otago.ac.nz.","acceptance":"Competitive — health sciences most selective","tuitionIntl":"International tuition 2026: ~NZ$26,000–$45,000/yr by faculty — the cheapest anchor among NZ's big universities (health professional programmes cost more; fees are per paper). PhD students pay the DOMESTIC rate (national policy, verified).","living":"Dunedin is one of NZ's cheapest student cities; visa requires NZ$20,000/yr living funds.","deadline":"Apply directly — confirm on otago.ac.nz.","scholarshipsHere":"Otago International Excellence Scholarships plus Manaaki placements.","scholarships":[],"sourceName":"University of Otago (official)","sourceUrl":"https://www.otago.ac.nz/study/fees/international-tuition-fees","verified":false}$sq$::jsonb);
