insert into public.universities (id, country, name, verified, data) values ($sq$tsinghua$sq$, $sq$China$sq$, $sq$Tsinghua University$sq$, false, $sq${"id":"tsinghua","name":"Tsinghua University","country":"China","city":"Beijing","flag":"🇨🇳","ranking":"China's #1 university — global top-20; engineering and CS powerhouse","knownFor":["Engineering","Computer Science","Architecture","Economics & Management","Public Policy"],"language":"Chinese-medium for most undergrad (HSK 5+); English-taught graduate programmes including the Schwarzman Master of Global Affairs.","entryGrades":"Extremely competitive — top grades plus interviews for international undergrad admission.","tests":"HSK 5+ for Chinese-medium; IELTS/TOEFL for English-taught — confirm per programme.","acceptance":"Extremely competitive","tuitionIntl":"Remarkably cheap for its rank: undergrad ¥26,000/yr (economics/management/law-type) to ¥30,000/yr (science/engineering) ≈ $3,600–$4,200 (official-derived); professional programmes more. Application fee ¥800.","living":"Beijing living is moderate (~$4,000–$6,000/yr as a student); university dormitories are cheap.","deadline":"International undergrad applications ~October–January for autumn entry — confirm on join-tsinghua.edu.cn.","scholarshipsHere":"Schwarzman Scholars (fully-funded one-year Master of Global Affairs, ages 18–28, deadline ~Sep 9) plus Tsinghua international scholarships and CSC places.","scholarships":[{"name":"Schwarzman Scholars","percentage":"Fully funded — tuition, room & board, travel, insurance, stipend (one-year Master of Global Affairs, English-medium)","whoQualifies":"Ages 18–28 (not yet 29 by Aug 1 of enrollment year) with a completed bachelor's; leadership-driven selection with interviews","howToApply":"Via schwarzmanscholars.org — deadline 9 Sep 2026 for the 2027-28 class (most passports)","deadlineMonth":9,"amountTier":1,"level":"Postgraduate","verified":true}],"sourceName":"Tsinghua University (official international admissions)","sourceUrl":"https://international.join-tsinghua.edu.cn/Admission1/Fees.htm","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$peking$sq$, $sq$China$sq$, $sq$Peking University (PKU)$sq$, false, $sq${"id":"peking","name":"Peking University (PKU)","country":"China","city":"Beijing","flag":"🇨🇳","ranking":"China's most storied comprehensive university — Tsinghua's great rival","knownFor":["Humanities","Law","Economics","Sciences","Medicine"],"language":"Chinese-medium for most undergrad (HSK 5+); English-taught graduate options including the Yenching Academy.","entryGrades":"Extremely competitive — confirm requirements on the official site.","tests":"HSK 5+ for Chinese-medium; IELTS/TOEFL for English-taught — confirm per programme.","acceptance":"Extremely competitive","tuitionIntl":"~¥26,000–¥30,000/yr for most undergrad programmes (official-derived ≈ $3,600–$4,200) — confirm on international.pku.edu.cn.","living":"Beijing living is moderate; dormitories cheap.","deadline":"~October–January for autumn entry — confirm on the official site.","scholarshipsHere":"Yenching Academy — fully-funded interdisciplinary China Studies master's (tuition + accommodation + travel + stipend); plus CSC places.","scholarships":[{"name":"Yenching Academy Scholarship","percentage":"Fully funded — tuition + accommodation + travel + living stipend (China Studies master's, English-medium)","whoQualifies":"Outstanding bachelor's graduates worldwide with strong interdisciplinary interest in China","howToApply":"Via yenchingacademy.pku.edu.cn — region-dependent deadlines ~Nov–Jan for autumn entry","deadlineMonth":12,"amountTier":1,"level":"Postgraduate","verified":true}],"sourceName":"Peking University (official)","sourceUrl":"https://www.yenchingacademy.pku.edu.cn/","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$fudan$sq$, $sq$China$sq$, $sq$Fudan University$sq$, false, $sq${"id":"fudan","name":"Fudan University","country":"China","flag":"🇨🇳","city":"Shanghai","ranking":"Elite C9 comprehensive university in Shanghai","knownFor":["Medicine (English MBBS)","Economics","Journalism","International Relations"],"language":"Chinese-medium for most programmes (HSK 4–5); English-taught options vary — confirm per programme.","entryGrades":"Varies by programme — confirm on the official site.","tests":"HSK for Chinese-medium; IELTS/TOEFL for some English programmes — confirm on the official site.","acceptance":"Varies by programme","tuitionIntl":"Not verified — typical Chinese English-taught fees run ¥20,000–¥40,000/yr (~$2,800–$5,600); confirm on the official site. MOE-approved English MBBS (IELTS/TOEFL required). Shanghai Government Scholarship stacks with CSC.","living":"China living costs are low (~$2,500–$5,000/yr; dormitories cheap). Post-study work visas are hard — standard permits usually need 2 years' experience.","deadline":"Most autumn intakes close ~Feb–May; CSC embassy route closes earlier (~Dec–Mar) — confirm on the official site.","scholarshipsHere":"Chinese Government Scholarship (CSC) — tuition + dormitory + ¥2,500–3,500/month stipend — via your Chinese embassy (Type A) or directly through the university (Type B); provincial scholarships often stack.","scholarships":[],"sourceName":"Official site","sourceUrl":"https://iso.fudan.edu.cn/","verified":false}$sq$::jsonb);
