insert into public.universities (id, country, name, verified, data) values ($sq$harvard$sq$, $sq$United States$sq$, $sq$Harvard University$sq$, true, $sq${"id":"harvard","name":"Harvard University","country":"United States","city":"Cambridge, Massachusetts","flag":"🇺🇸","ranking":"The world's most famous university","knownFor":["Economics","Government","Computer Science","Pre-Law & Pre-Med tracks","Liberal Arts"],"language":"English-medium instruction","entryGrades":"The hardest admission anywhere (~3–4% acceptance) — top grades, testing, essays, activities and recommendations all matter.","tests":"SAT/ACT policies and TOEFL/IELTS/Duolingo — confirm the current cycle's requirements.","acceptance":"Extremely competitive (~3–4%)","tuitionIntl":"Sticker ~$85,000+/yr all-in — but aid changes everything (verified): NEED-BLIND for internationals, FREE below $100k family income (all billed costs + $2,000 start-up and launch grants), tuition-free below $200k, full-need aid above that.","living":"Included in the cost of attendance and covered by aid for low-income families.","deadline":"Restrictive Early Action ~Nov 1; Regular Decision ~Jan 1 (Common App). CSS Profile for aid alongside.","scholarshipsHere":"Financial aid IS the scholarship: identical need-based packages for internationals and Americans (verified). If your family earns under $100k, Harvard is free — the barrier is admission, not money.","scholarships":[{"name":"Harvard Need-Based Aid (internationals included)","percentage":"Free below $100k family income; tuition-free below $200k; full-need above (verified 2025-26)","whoQualifies":"All admitted students regardless of citizenship — need-blind admission","howToApply":"CSS Profile + aid documents with your admission application","deadlineMonth":1,"amountTier":1,"level":"Undergraduate","verified":true}],"sourceName":"Harvard College (official financial aid)","sourceUrl":"https://college.harvard.edu/financial-aid","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$mit$sq$, $sq$United States$sq$, $sq$Massachusetts Institute of Technology (MIT)$sq$, true, $sq${"id":"mit","name":"Massachusetts Institute of Technology (MIT)","country":"United States","city":"Cambridge, Massachusetts","flag":"🇺🇸","ranking":"The world's premier STEM university","knownFor":["Engineering","Computer Science","Physics","Economics","AI"],"language":"English-medium instruction","entryGrades":"Extreme (~4% acceptance; international rate lower). SAT/ACT REQUIRED — MIT reinstated testing.","tests":"SAT/ACT required; TOEFL/IELTS for non-native speakers — confirm minimums.","acceptance":"Extremely competitive","tuitionIntl":"Sticker ~$85,000/yr all-in — but MIT is NEED-BLIND for internationals and meets 100% of demonstrated need for all four years (verified).","living":"Covered within need-based aid for qualifying families.","deadline":"Early Action ~Nov 1; Regular ~Jan — via MIT's own application portal (not Common App).","scholarshipsHere":"Need-based aid meets full need for internationals (verified) — no merit scholarships exist; everything is need-based.","scholarships":[],"sourceName":"MIT Admissions (official)","sourceUrl":"https://mitadmissions.org/afford/","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$stanford$sq$, $sq$United States$sq$, $sq$Stanford University$sq$, false, $sq${"id":"stanford","name":"Stanford University","country":"United States","city":"Stanford, California","flag":"🇺🇸","ranking":"The Silicon Valley university","knownFor":["Computer Science","Engineering","Business","Entrepreneurship"],"language":"English-medium instruction","entryGrades":"Extreme (~4% acceptance).","tests":"Confirm current SAT/ACT policy; TOEFL/IELTS for non-native speakers.","acceptance":"Extremely competitive","tuitionIntl":"Sticker ~$87,000/yr all-in. Stanford meets full need for admitted internationals but is need-AWARE for them — applying for aid is considered in admission (unlike the 10 need-blind schools).","living":"Bay Area is expensive; aid covers need for admitted aided students.","deadline":"Restrictive Early Action ~Nov 1; Regular ~Jan 5 (Common App).","scholarshipsHere":"Full-need aid if admitted with aid; Knight-Hennessy Scholars fully funds graduate study across all Stanford schools.","scholarships":[],"sourceName":"Stanford (official financial aid)","sourceUrl":"https://financialaid.stanford.edu/","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$amherst$sq$, $sq$United States$sq$, $sq$Amherst College$sq$, true, $sq${"id":"amherst","name":"Amherst College","country":"United States","city":"Amherst, Massachusetts","flag":"🇺🇸","ranking":"Top liberal-arts college — representative of the elite LAC route internationals overlook","knownFor":["Liberal Arts","Economics","Mathematics","Open Curriculum"],"language":"English-medium instruction","entryGrades":"Extremely competitive (~7–9% acceptance) — holistic.","tests":"Confirm current testing policy; TOEFL/IELTS for non-native speakers.","acceptance":"Extremely competitive","tuitionIntl":"Sticker ~$85,000/yr all-in — but NEED-BLIND for ALL applicants including internationals, meeting 100% of need with NO loans (verified).","living":"Residential campus; covered within aid.","deadline":"ED ~Nov 1; RD ~Jan 3 (Common App).","scholarshipsHere":"Full need-based aid, loan-free, need-blind for internationals (verified). Sister elite LACs — Bowdoin, Williams, Swarthmore — offer similar generosity; smaller names abroad, huge aid.","scholarships":[],"sourceName":"Amherst College (official financial aid)","sourceUrl":"https://www.amherst.edu/admission/financial-aid","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$nyu$sq$, $sq$United States$sq$, $sq$New York University (NYU)$sq$, false, $sq${"id":"nyu","name":"New York University (NYU)","country":"United States","city":"New York City","flag":"🇺🇸","ranking":"Hosts more international students than any other US university","knownFor":["Business (Stern)","Film (Tisch)","Computer Science","Economics","Global Campuses"],"language":"English-medium instruction","entryGrades":"Competitive (~8–12% acceptance overall, varies by school).","tests":"Test-flexible policies — confirm; TOEFL/IELTS for non-native speakers.","acceptance":"Competitive — varies by school","tuitionIntl":"Sticker ~$90,000/yr all-in in Manhattan and aid for internationals is LIMITED — most pay near sticker. The aid-rich alternative is NYU ABU DHABI (also in this app), where need-based aid can cover nearly everything.","living":"New York City — among the priciest student cities on earth.","deadline":"ED I ~Nov 1, ED II ~Jan 1, RD ~Jan 5 (Common App).","scholarshipsHere":"Limited merit/need aid for internationals at the NYC campus — compare seriously with NYU Abu Dhabi before committing.","scholarships":[],"sourceName":"NYU (official)","sourceUrl":"https://www.nyu.edu/admissions/undergraduate-admissions.html","verified":false}$sq$::jsonb);
