insert into public.universities (id, country, name, verified, data) values ($sq$melbourne$sq$, $sq$Australia$sq$, $sq$University of Melbourne$sq$, false, $sq${"id":"melbourne","name":"University of Melbourne","country":"Australia","city":"Melbourne","flag":"🇦🇺","ranking":"Australia's #1-ranked university","knownFor":["Medicine","Law","Engineering","Computer Science","Arts"],"language":"English-medium instruction","entryGrades":"Highly competitive — assessed on national qualifications (A-Levels/IB/etc.); confirm per course.","tests":"IELTS 6.5+ typically (higher for medicine/law) — confirm on study.unimelb.edu.au.","acceptance":"Highly competitive — varies by course","tuitionIntl":"Set per course at the top of the Australian range (~AU$45,000–$60,000+/yr for most undergrad) — confirm on study.unimelb.edu.au. Visa also requires AU$29,710/yr living funds + AU$2,500 travel (verified).","living":"Melbourne is expensive but slightly cheaper than Sydney; the official visa benchmark is AU$29,710/yr.","deadline":"Semester 1 (Feb) applications generally ~Oct–Dec; Semester 2 (Jul) ~Apr–May — confirm per course.","scholarshipsHere":"Melbourne International Undergraduate Scholarship (fee remissions up to 100% for a small number — confirm current terms); research degrees widely funded via RTP. Post-study 485 visa: 2 years (3 for research/PhD).","scholarships":[],"sourceName":"University of Melbourne (official)","sourceUrl":"https://study.unimelb.edu.au/","verified":false}$sq$::jsonb);
