insert into public.universities (id, country, name, verified, data) values ($sq$wits$sq$, $sq$South Africa$sq$, $sq$University of the Witwatersrand (Wits)$sq$, true, $sq${"id":"wits","name":"University of the Witwatersrand (Wits)","country":"South Africa","city":"Johannesburg","flag":"🇿🇦","ranking":"Johannesburg's flagship research university — Nelson Mandela's alma mater","knownFor":["Mining Engineering","Medicine","Law","Business","Palaeosciences"],"language":"English-medium instruction","entryGrades":"Competitive — points-based on final school results; health sciences most selective. Confirm per programme.","tests":"IELTS/TOEFL if your schooling was not in English — confirm on wits.ac.za.","acceptance":"Competitive — varies by faculty","tuitionIntl":"Verified 2026 policy: SADC citizens pay LOCAL tuition + R6,970 International Registration Fee; non-SADC undergraduates pay DOUBLE local tuition. 75% of tuition is due at registration, balance by 30 June.","living":"Johannesburg living is affordable by global standards — budget sensibly for safety-conscious housing.","deadline":"Applications generally close ~30 June (health sciences) to ~30 September for the following year — confirm on wits.ac.za.","scholarshipsHere":"SADC citizens automatically get local fees (see the SADC entry); Mandela Rhodes tenable for postgraduate study; Wits merit awards on the official site.","scholarships":[],"sourceName":"Wits University (official)","sourceUrl":"https://www.wits.ac.za/internationalstudents/financial-information/fee-structure/","verified":true}$sq$::jsonb);
