insert into public.universities (id, country, name, verified, data) values ($sq$trinity$sq$, $sq$Ireland$sq$, $sq$Trinity College Dublin (TCD)$sq$, true, $sq${"id":"trinity","name":"Trinity College Dublin (TCD)","country":"Ireland","city":"Dublin","flag":"🇮🇪","ranking":"Ireland's most famous and highest-ranked university (founded 1592)","knownFor":["Law","English Literature","Computer Science","Medicine","Business"],"language":"English-medium instruction","entryGrades":"Competitive — CAO points or equivalent international qualifications; confirm per course.","tests":"IELTS 6.5+ typically — confirm on tcd.ie.","acceptance":"Competitive — varies by course","tuitionIntl":"Non-EU tuition €21,570–€29,570/yr by course for 2026/27 (verified, tcd.ie); medicine higher. The visa additionally requires showing €12,000/yr living funds (verified).","living":"Dublin is expensive — the €12,000 visa benchmark is a floor; budget more realistically.","deadline":"CAO by ~1 February for undergrad (some non-EU direct routes accept later) — confirm on tcd.ie.","scholarshipsHere":"Trinity Global Excellence Scholarships (partial merit — confirm terms); Government of Ireland IES for master's/PhD (€10,000 + full fee waiver, deadline ~12 March). Stamp 1G stay-back: 12 months (bachelor's) / 24 months (master's+).","scholarships":[],"sourceName":"Trinity College Dublin (official)","sourceUrl":"https://www.tcd.ie/courses/undergraduate/fees/","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$tu-dublin$sq$, $sq$Ireland$sq$, $sq$Technological University Dublin (TU Dublin)$sq$, false, $sq${"id":"tu-dublin","name":"Technological University Dublin (TU Dublin)","country":"Ireland","city":"Dublin","flag":"🇮🇪","ranking":"Ireland's first technological university — the VALUE option in Dublin","knownFor":["Engineering","Computing","Hospitality & Culinary Arts","Media","Architecture"],"language":"English-medium instruction","entryGrades":"More accessible than the traditional universities; varies by course — confirm on tudublin.ie.","tests":"IELTS 6.0+ typically — confirm on tudublin.ie.","acceptance":"Accessible — varies by course","tuitionIntl":"Non-EU undergraduate ~€11,650–€12,500/yr per official-derived listings — the cheapest Dublin university tier (confirm on tudublin.ie). Same €12,000/yr visa living requirement as everywhere.","living":"Dublin costs apply — the fee savings vs Trinity/UCD (~€10,000+/yr) are the draw.","deadline":"CAO by ~1 February — confirm on tudublin.ie.","scholarshipsHere":"Same Stamp 1G stay-back (12–24 months) and Dublin job market as the pricier universities — a strong value pick. GOI-IES applies for postgrad.","scholarships":[],"sourceName":"TU Dublin (official)","sourceUrl":"https://www.tudublin.ie/study/international-students/","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$ucd$sq$, $sq$Ireland$sq$, $sq$University College Dublin (UCD)$sq$, false, $sq${"id":"ucd","name":"University College Dublin (UCD)","country":"Ireland","city":"Dublin","flag":"🇮🇪","ranking":"Ireland's largest university — huge international cohort","knownFor":["Business (Smurfit)","Engineering","Agriculture & Food Science","Medicine"],"language":"English-medium instruction","entryGrades":"CAO points or equivalent international qualifications — confirm per course on the official site.","tests":"IELTS / TOEFL required; the minimum varies by course — confirm on the official site.","acceptance":"Varies by course","tuitionIntl":"Not verified — Irish non-EU undergraduate fees typically run €12,000–€30,000/yr by course (medicine far higher); confirm on the official site. The visa requires €12,000/yr living funds on top of tuition (verified).","living":"Dublin is the priciest; Cork, Galway, Limerick and Maynooth run noticeably cheaper.","deadline":"Undergrad via the CAO by ~1 February; postgraduate applications are direct and often rolling — confirm on the official site.","scholarshipsHere":"Government of Ireland IES for master's/PhD (€10,000 + full fee waiver, ~12 March deadline, 60 awards); university merit awards vary. Stamp 1G stay-back: 12 months (bachelor's) / 24 months (master's+), full work rights.","scholarships":[],"sourceName":"Official site","sourceUrl":"https://www.ucd.ie/global/","verified":false}$sq$::jsonb);
