insert into public.universities (id, country, name, verified, data) values ($sq$polimi$sq$, $sq$Italy$sq$, $sq$Politecnico di Milano (PoliMi)$sq$, true, $sq${"id":"polimi","name":"Politecnico di Milano (PoliMi)","country":"Italy","city":"Milan","flag":"🇮🇹","ranking":"Italy's top technical university — global top-20 in design, top-50 in engineering","knownFor":["Design","Architecture","Mechanical & Aerospace Engineering","Computer Science"],"language":"Most MSc programmes English-taught; bachelor's mixed Italian/English.","entryGrades":"Competitive — GPA-ranked admission for English MSc; ~3.0/4.0 realistic for admission, ~3.3+ for the top scholarships.","tests":"IELTS/TOEFL for English programmes (certificate deadline ~late Feb for Early Bird) — confirm on polimi.it.","acceptance":"Competitive — varies by programme","tuitionIntl":"Standard non-EU MSc tuition ~€3,886/yr (verified) — already among the lowest for a top technical university; income-based reductions can lower it further.","living":"Milan is Italy's most expensive city (~€1,000–1,400/month). DSU regional grants (fee waiver + up to ~€6,000–8,000 + housing + meals) apply for low-income admits.","deadline":"EARLY BIRD window 1 Oct–1 Dec for the following autumn — apply then for automatic scholarship consideration; later windows lack scholarship priority.","scholarshipsHere":"Merit-Based International Scholarships, awarded automatically by ranking to Early Bird MSc applicants: Platinum €10,000/yr + full waiver, Gold €8,000 + waiver, Silver waiver only (~€170 admin fee remains). Also an Invest Your Talent partner (tuition waiver + €900/month + guaranteed internship).","scholarships":[{"name":"PoliMi Merit-Based International Scholarships","percentage":"Platinum €10,000/yr + full waiver · Gold €8,000 + waiver · Silver waiver only","whoQualifies":"Top-ranked non-EU applicants to English-taught MSc programmes applying in the Early Bird window (~3.3+/4.0 GPA realistic for Gold/Platinum)","howToApply":"Automatic with an Early Bird application (1 Oct–1 Dec) — no separate form","deadlineMonth":12,"amountTier":1,"level":"Postgraduate","verified":true}],"sourceName":"Politecnico di Milano (official)","sourceUrl":"https://www.polimi.it/en/prospective-students/how-much-does-it-cost/scholarships","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$bologna$sq$, $sq$Italy$sq$, $sq$University of Bologna (Unibo)$sq$, true, $sq${"id":"bologna","name":"University of Bologna (Unibo)","country":"Italy","city":"Bologna","flag":"🇮🇹","ranking":"The oldest university in the world (1088) — large, comprehensive, very international","knownFor":["Law","Humanities","Economics","Engineering","Agriculture"],"language":"Many English-taught bachelor's and master's programmes.","entryGrades":"Competitive for scholarship consideration (SAT/TOLC for bachelor's, GRE for master's grants); admission itself varies by programme.","tests":"IELTS/TOEFL for English programmes; SAT/TOLC or GRE needed for the Unibo grant schemes — confirm on unibo.it.","acceptance":"Competitive — varies by programme","tuitionIntl":"Income-based via ISEE Parificato: €0–~€4,000/yr; even full-waiver students pay ~€157 in fixed charges (verified). Non-EU applicants pre-enrol via Universitaly.","living":"Bologna is a classic student city (~€800–1,100/month); ER-GO is the regional DSU agency.","deadline":"Programme-dependent; scholarship calls close in the first half of the year via Studenti Online — confirm on unibo.it.","scholarshipsHere":"Unibo Actions (verified): Action 1 tuition waivers, Action 2 €11,000 gross study grant for master's; plus International Talents @Unibo (€6,500 + full exemption for 2 years, test-score based). DSU (ER-GO) stacks for low-income students.","scholarships":[{"name":"Unibo Actions & International Talents","percentage":"Action 2: €11,000 gross grant (master's) · Action 1: tuition waivers · International Talents: €6,500 + full exemption ×2 years","whoQualifies":"International-qualification holders enrolling at Bologna; ranked on SAT/TOLC (bachelor's) or GRE (master's); age caps commonly apply (~under 30)","howToApply":"Via Studenti Online (studenti.unibo.it) — calls close ~first half of the year","deadlineMonth":4,"amountTier":1,"level":"Postgraduate","verified":true}],"sourceName":"University of Bologna (official)","sourceUrl":"https://www.unibo.it/en/study/study-grants-and-subsidies","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$bocconi$sq$, $sq$Italy$sq$, $sq$Bocconi University$sq$, false, $sq${"id":"bocconi","name":"Bocconi University","country":"Italy","city":"Milan","flag":"🇮🇹","ranking":"Italy's elite private business university — Europe's top tier for economics and finance","knownFor":["Economics","Finance","Management","Data Science","Law"],"language":"Full English-taught tracks at all levels.","entryGrades":"Highly competitive — Bocconi test or SAT + strong school record; confirm per programme.","tests":"Bocconi admission test or SAT; IELTS/TOEFL — confirm on unibocconi.it.","acceptance":"Highly competitive","tuitionIntl":"Income-based ~€3,500–€14,000+/yr assessed via ISEE (a flat higher rate can apply to internationals) — far above public universities, but with genuine aid attached.","living":"Milan costs (~€1,000–1,400/month); ISU package includes dorm discounts and a daily free meal.","deadline":"Admission rounds run autumn–spring; apply for aid via the single \"Bocconi4Access to Education\" application — confirm on unibocconi.it.","scholarshipsHere":"ISU Bocconi need-based package (verified): full/partial waiver + cash up to €8,000/yr + dorm discounts + one free meal/day. Merit scholarships are automatic for strong admits. Also an Invest Your Talent partner.","scholarships":[{"name":"ISU Bocconi Need-Based Package","percentage":"Full/partial tuition waiver + up to €8,000/yr cash + dorm discounts + one free meal/day","whoQualifies":"Low/middle-income admitted students (ISEE/ISEE Parificato assessed) — internationals included","howToApply":"Single \"Bocconi4Access to Education\" application alongside admission","amountTier":1,"level":"Undergraduate","verified":true}],"sourceName":"Bocconi University (official funding pages)","sourceUrl":"https://www.unibocconi.it/en/applying-bocconi/bachelor-and-law-programs/funding","verified":false}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$sapienza$sq$, $sq$Italy$sq$, $sq$Sapienza University of Rome$sq$, false, $sq${"id":"sapienza","name":"Sapienza University of Rome","country":"Italy","city":"Rome","flag":"🇮🇹","ranking":"Europe's largest university — world #1 for Classics & Archaeology","knownFor":["Classics & Archaeology","Medicine (English IMAT)","Engineering","Physics"],"language":"Mostly Italian-taught bachelor's; English-taught master's and IMAT medicine where noted — confirm per programme.","entryGrades":"Varies by programme; English medicine requires the IMAT exam (register ~July, sit ~September).","tests":"IELTS/TOEFL for English programmes (many IMAT universities skip it); Italian B2 for Italian-taught — confirm per programme.","acceptance":"Varies by programme — IMAT medicine is seat-limited and competitive","tuitionIntl":"Income-based public fees €0–~€4,000/yr via ISEE Parificato (below ~€13,000–26,000 ISEE many charge zero/minimum) — not individually verified; confirm on the official site. Non-EU applicants pre-enrol via Universitaly (mandatory, verified).","living":"Roughly €700–€1,200/month by city; DSU regional grants (fee waiver + up to ~€6,000–8,000/yr + housing + meals) are open to low-income internationals — regional deadlines ~Jul–Sep, separate from admission.","deadline":"Programme windows vary (~spring for autumn entry); IMAT registration ~July. Confirm on the official site and Universitaly.","scholarshipsHere":"DSU regional grant (see the Italy scholarship entries), MAECI (~€900/month) and Invest Your Talent (waiver + €900/month + guaranteed internship, selected countries) all apply — plus per-university awards.","scholarships":[],"sourceName":"Official site","sourceUrl":"https://www.uniroma1.it/en/","verified":false}$sq$::jsonb);
