insert into public.universities (id, country, name, verified, data) values ($sq$semmelweis$sq$, $sq$Hungary$sq$, $sq$Semmelweis University$sq$, false, $sq${"id":"semmelweis","name":"Semmelweis University","country":"Hungary","city":"Budapest","flag":"🇭🇺","ranking":"Hungary's dedicated medical university (1769) — Europe's top tier for medicine","knownFor":["Medicine","Dentistry","Pharmacy","Health Sciences"],"language":"Full English (and German) tracks.","entryGrades":"Entrance examination (biology/chemistry/physics + English) — competitive; confirm on semmelweis.hu.","tests":"Own entrance exam; no IELTS typically required — confirm.","acceptance":"Competitive — medicine seats are limited","tuitionIntl":"Medicine ~$18,200/yr (~$109,000 for the 6-year MD, official-derived) — roughly half UK/US medical costs for an EU-recognised degree.","living":"Budapest ~€500–800/month — low for a European capital.","deadline":"Direct applications ~spring for autumn entry; the Stipendium Hungaricum route closes 15 January.","scholarshipsHere":"Stipendium Hungaricum full scholarships place students here (medicine is the most competitive SH category) — 100% tuition + stipend + housing + insurance.","scholarships":[],"sourceName":"Semmelweis University (official)","sourceUrl":"https://semmelweis.hu/english/","verified":false}$sq$::jsonb);
