insert into public.universities (id, country, name, verified, data) values ($sq$utokyo$sq$, $sq$Japan$sq$, $sq$University of Tokyo (UTokyo)$sq$, true, $sq${"id":"utokyo","name":"University of Tokyo (UTokyo)","country":"Japan","city":"Tokyo","flag":"🇯🇵","ranking":"Japan's #1 university","knownFor":["Engineering","Science","Law","Medicine","Economics"],"language":"Mostly Japanese-taught; PEAK offers English-taught undergraduate tracks, and the GSC transfer programme is fully English.","entryGrades":"Extremely competitive — PEAK uses holistic international admissions; Japanese tracks use the EJU exam.","tests":"PEAK: TOEFL/IELTS + school record + interviews. Japanese track: EJU + JLPT — confirm on u-tokyo.ac.jp.","acceptance":"Extremely competitive","tuitionIntl":"Tuition ¥642,960/yr (verified — raised from the ¥535,800 national standard, Japan's first hike in 20 years) + one-time ¥282,000 admission fee ≈ still only ~$4,300/yr for the country's top university. GSC transfer students receive ¥150,000/month + housing support (verified).","living":"Tokyo is Japan's priciest city (~¥130,000–180,000/month) — dorms help.","deadline":"PEAK applications ~Dec–Jan for autumn entry; MEXT embassy route opens ~April a year ahead.","scholarshipsHere":"MEXT full scholarships (embassy and university routes — see the Japan scholarship entry); PEAK-specific aid; JASSO monthly awards.","scholarships":[],"sourceName":"University of Tokyo (official)","sourceUrl":"https://www.u-tokyo.ac.jp/en/prospective-students/tuition_fees.html","verified":true}$sq$::jsonb);
insert into public.universities (id, country, name, verified, data) values ($sq$apu-japan$sq$, $sq$Japan$sq$, $sq$Ritsumeikan Asia Pacific University (APU)$sq$, false, $sq${"id":"apu-japan","name":"Ritsumeikan Asia Pacific University (APU)","country":"Japan","city":"Beppu (Kyushu)","flag":"🇯🇵","ranking":"Japan's international outlier — HALF the student body is international (90+ countries)","knownFor":["International Management","Asia Pacific Studies","Sustainability & Tourism"],"language":"Fully English-taught tracks — no Japanese needed to start (you learn it alongside).","entryGrades":"Accessible-to-moderate — holistic document-based admission designed for international applicants.","tests":"IELTS/TOEFL or equivalent — confirm on apu.ac.jp.","acceptance":"Accessible — designed for internationals","tuitionIntl":"~¥1.3M–1.5M/yr sticker — but 30–65% tuition-reduction scholarships are COMMON and every applicant is considered automatically with the admission application (official-derived; confirm on apu.ac.jp).","living":"Beppu is far cheaper than Tokyo (~¥70,000–100,000/month) — an onsen town on Kyushu.","deadline":"Multiple intakes (April/September) with rolling document deadlines — confirm on apu.ac.jp.","scholarshipsHere":"Tuition Reduction Scholarship (30–65%, automatic consideration), JASSO, and MEXT places — the easiest genuine entry into Japanese higher education for non-Japanese speakers.","scholarships":[{"name":"APU Tuition Reduction Scholarship","percentage":"30–65% off tuition — commonly awarded","whoQualifies":"International applicants — assessed automatically from the admission application","howToApply":"Automatic with the application (indicate financial need in the form)","amountTier":2,"level":"Undergraduate","verified":false}],"sourceName":"APU (official admissions)","sourceUrl":"https://admissions.apu.ac.jp/costs_scholarships/","verified":false}$sq$::jsonb);
