insert into public.universities (id, country, name, verified, data) values ($sq$kaist$sq$, $sq$South Korea$sq$, $sq$KAIST$sq$, true, $sq${"id":"kaist","name":"KAIST","country":"South Korea","city":"Daejeon","flag":"🇰🇷","ranking":"Korea's MIT — fully English-taught STEM institute","knownFor":["Computer Science","Electrical Engineering","Robotics","Physics","Entrepreneurship"],"language":"FULLY English-taught — no Korean required to graduate.","entryGrades":"Competitive holistic STEM admission — strong maths/science record; genuinely accessible to strong students worldwide.","tests":"English proficiency evidence (flexible routes exist) — confirm on admission.kaist.ac.kr.","acceptance":"Competitive","tuitionIntl":"Effectively FREE for admitted international undergraduates (verified): the KAIST Scholarship grants full tuition for 8 semesters + ₩350,000/month + insurance, automatically — just select it in the admission application. Renewal needs GPA 2.7/4.3.","living":"Daejeon is much cheaper than Seoul (~₩600,000–900,000/month); the stipend covers a real share.","deadline":"Early round ~September, regular ~January for autumn entry — confirm on admission.kaist.ac.kr.","scholarshipsHere":"KAIST Scholarship (automatic full funding, verified); GKS places also exist. One of the best value propositions in global STEM education.","scholarships":[{"name":"KAIST Scholarship (international undergraduates)","percentage":"Full tuition (8 semesters) + ₩350,000/month + health insurance","whoQualifies":"All admitted international undergraduates who select it in the application; renew with GPA 2.7/4.3","howToApply":"Choose \"KAIST Scholarship\" in the financial-resources section of the admission application — no separate form","amountTier":1,"level":"Undergraduate","verified":true}],"sourceName":"KAIST (official admissions)","sourceUrl":"https://admission.kaist.ac.kr/intl-graduate/FinancialSupport/Scholarship/KAISTScholarship","verified":true}$sq$::jsonb);
