insert into public.universities (id, country, name, verified, data) values ($sq$helsinki$sq$, $sq$Finland$sq$, $sq$University of Helsinki$sq$, false, $sq${"id":"helsinki","name":"University of Helsinki","country":"Finland","city":"Helsinki","flag":"🇫🇮","ranking":"Finland's flagship — Nordic top-tier research (~€13,000–18,000/yr before waivers)","knownFor":["Computer Science","Life Sciences","Education","Law"],"language":"English-taught programmes plentiful at both bachelor's and master's — confirm per programme. Finnish/Swedish helps for jobs later.","entryGrades":"Merit-based via the national Studyinfo system; some programmes use entrance exams or SAT.","tests":"IELTS 6.0–6.5 / TOEFL typical — confirm per programme.","acceptance":"Moderately competitive — waiver tiers track your ranking","tuitionIntl":"Non-EU €8,000–€20,000/yr (verified country range; per-university figures in the note are typical) — BUT 50–100% tuition waivers are routinely awarded AUTOMATICALLY with your application at most universities. Confirm on the official site.","living":"~€800–1,100/month; the residence permit requires ~€800/month in funds — confirm on migri.fi.","deadline":"ONE national portal (studyinfo.fi) — main joint application in JANUARY for autumn entry; some rolling windows.","scholarshipsHere":"Automatic waiver consideration (50–100%) with the application — apply early with strong grades; waivers cover tuition, not living. Post-study: a 2-YEAR job-seeking/business residence permit (verified), usable within 5 years of graduating.","scholarships":[],"sourceName":"Official site","sourceUrl":"https://www.helsinki.fi/en/admissions-and-education","verified":false}$sq$::jsonb);
